INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('biologia', 'bachillerato', '{1}', '["La glucosa entra en la célula y se fosforila en el citoplasma","Se descompone en dos moléculas de piruvato generando 2 ATP netos","El piruvato entra en la mitocondria y se convierte en acetil-CoA","El acetil-CoA ingresa en el ciclo de Krebs produciendo NADH y FADH2","Los electrones pasan a la cadena de transporte generando hasta 36 ATP"]'),
('biologia', 'bachillerato', '{1}', '["La célula entra en la fase G1 del ciclo celular y crece en tamaño","En la fase S se duplica todo el ADN formando cromátidas hermanas","Durante la fase G2 se sintetizan las proteínas necesarias para la división","En la mitosis los cromosomas se alinean y se separan hacia los polos","La citocinesis divide el citoplasma originando dos células hijas idénticas"]'),
('biologia', 'bachillerato', '{1}', '["En la profase I los cromosomas homólogos se aparean formando bivalentes","Se produce el sobrecruzamiento intercambiando fragmentos entre cromátidas no hermanas","En la metafase I los bivalentes se alinean en la placa ecuatorial","En la anafase I los homólogos se separan hacia polos opuestos de la célula","La meiosis II separa las cromátidas hermanas generando cuatro células haploides"]'),
('biologia', 'bachillerato', '{1}', '["La membrana plasmática está formada por una bicapa de fosfolípidos","Las proteínas integrales atraviesan la bicapa permitiendo el transporte selectivo","El colesterol se intercala entre los fosfolípidos regulando la fluidez de la membrana","Los glúcidos se unen a proteínas y lípidos formando el glucocáliz externo","Esta estructura permite el intercambio controlado de sustancias con el medio"]'),
('biologia', 'bachillerato', '{1}', '["Los ácidos grasos se activan en el citoplasma uniéndose a la coenzima A","El acil-CoA entra en la mitocondria mediante el transportador de carnitina","En la beta-oxidación se eliminan dos carbonos en cada vuelta del ciclo","Cada vuelta produce un acetil-CoA junto con NADH y FADH2","El acetil-CoA entra en el ciclo de Krebs completando la degradación del ácido graso"]'),
('biologia', 'bachillerato', '{1}', '["El retículo endoplasmático rugoso sintetiza proteínas con destino a la secreción","Las proteínas se empaquetan en vesículas de transición hacia el aparato de Golgi","En el Golgi las proteínas se modifican añadiendo glucosilaciones y señales de destino","Las vesículas de secreción se forman en la cara trans del aparato de Golgi","Las vesículas se fusionan con la membrana plasmática liberando su contenido al exterior"]'),
('biologia', 'bachillerato', '{1}', '["La célula vegetal capta luz solar a través de los pigmentos del cloroplasto","En la fase luminosa el agua se descompone liberando oxígeno y generando NADPH","Los fotones excitan los electrones de la clorofila que pasan por la cadena de transporte","Se genera un gradiente de protones que impulsa la síntesis de ATP por quimiosmosis","El ATP y NADPH se utilizan en el ciclo de Calvin para fijar CO2 y producir glucosa"]'),
('biologia', 'bachillerato', '{1}', '["La enzima se une al sustrato formando el complejo enzima-sustrato en el centro activo","La energía de activación de la reacción disminuye gracias a la catálisis enzimática","El sustrato se transforma en productos que se liberan del centro activo","La enzima queda libre y puede catalizar una nueva reacción sin consumirse","La velocidad de la reacción depende de la concentración de sustrato y la temperatura"]'),
('biologia', 'bachillerato', '{1}', '["Los lisosomas contienen enzimas hidrolíticas sintetizadas en el retículo endoplasmático rugoso","Una vesícula endocítica con material externo se fusiona con un lisosoma primario","Se forma un lisosoma secundario donde se digiere el contenido de la vesícula","Los nutrientes resultantes pasan al citoplasma para ser reutilizados por la célula","Los residuos no digeridos se expulsan al exterior mediante exocitosis"]'),
('biologia', 'bachillerato', '{1}', '["En la interfase los cromosomas están descondensados en forma de cromatina","La cromatina se condensa al inicio de la profase haciéndose visible al microscopio","Los cromosomas alcanzan su máxima condensación en la metafase alineándose en el ecuador","En la anafase las fibras del huso tiran de los centrómeros separando las cromátidas","En la telofase los cromosomas se descondensan y se reconstruye la envoltura nuclear"]'),
('biologia', 'bachillerato', '{1}', '["La fermentación láctica comienza con la glucólisis en el citoplasma celular","Se obtienen dos moléculas de piruvato y dos de ATP sin consumir oxígeno","El piruvato se reduce a ácido láctico regenerando el NAD+ necesario para continuar","Este proceso ocurre en las fibras musculares durante el ejercicio intenso","La acumulación de ácido láctico provoca fatiga muscular y debe eliminarse tras el esfuerzo"]'),
('biologia', 'bachillerato', '{1}', '["La fermentación alcohólica parte de la glucosa que se descompone por glucólisis","El piruvato se descarboxila produciendo acetaldehído y liberando CO2","El acetaldehído se reduce a etanol regenerando NAD+ para la glucólisis","Este proceso es realizado por levaduras en condiciones anaeróbicas","Se aprovecha industrialmente para fabricar pan, cerveza y vino"]'),
('biologia', 'bachillerato', '{1}', '["El ADN se organiza enrollándose alrededor de octámeros de histonas formando nucleosomas","Los nucleosomas se empaquetan en una fibra de 30 nm llamada solenoide","El solenoide forma bucles anclados a una estructura proteica llamada scaffold","En la mitosis el empaquetamiento alcanza su máximo nivel formando el cromosoma metafásico","Esta compactación permite repartir el material genético equitativamente entre las células hijas"]'),
('biologia', 'bachillerato', '{1}', '["La mitocondria tiene una membrana externa lisa y una interna con crestas mitocondriales","En la matriz mitocondrial se localiza el ciclo de Krebs y el ADN mitocondrial propio","Las crestas aumentan la superficie para alojar los complejos de la cadena respiratoria","Los electrones del NADH y FADH2 pasan por los complejos bombeando protones al espacio intermembrana","La ATP sintasa aprovecha el gradiente de protones para sintetizar ATP por fosforilación oxidativa"]'),
('biologia', 'bachillerato', '{1}', '["La replicación del ADN comienza en los orígenes de replicación donde se abre la doble hélice","La helicasa separa las dos hebras y las topoisomerasas eliminan la tensión del superenrollamiento","La primasa sintetiza un cebador de ARN en cada hebra molde","La ADN polimerasa III añade nucleótidos en dirección cinco prima a tres prima","La ADN ligasa une los fragmentos de Okazaki completando la hebra retardada"]'),
('biologia', 'bachillerato', '{1}', '["El ciclo de Krebs comienza con la condensación del acetil-CoA con el oxalacetato","Se forma citrato que se isomeriza a isocitrato mediante la aconitasa","El isocitrato se descarboxila oxidativamente produciendo alfa-cetoglutarato y NADH","Sucesivas reacciones regeneran el oxalacetato completando el ciclo en ocho pasos","Cada vuelta produce 3 NADH, 1 FADH2, 1 GTP y 2 moléculas de CO2"]'),
('biologia', 'bachillerato', '{1}', '["El cloroplasto tiene una doble membrana externa y un sistema de tilacoides en su interior","Los tilacoides se apilan formando granas conectadas por lamelas del estroma","En la membrana tilacoidal se encuentran los fotosistemas I y II con la clorofila","La luz excita los electrones de la clorofila iniciando la fase luminosa de la fotosíntesis","En el estroma se desarrolla el ciclo de Calvin que fija el CO2 en moléculas orgánicas"]'),
('biologia', 'bachillerato', '{1}', '["El ribosoma está formado por dos subunidades de ARN ribosómico y proteínas","La subunidad menor se une al ARNm reconociendo el codón de inicio AUG","La subunidad mayor se acopla formando el ribosoma funcional con sus sitios A, P y E","Los aminoácidos se unen mediante enlaces peptídicos catalizados por la peptidil transferasa","Al llegar a un codón de parada los factores de liberación disocian el ribosoma del ARNm"]'),
('biologia', 'bachillerato', '{1}', '["La difusión simple permite el paso de moléculas pequeñas apolares a través de la bicapa lipídica","La difusión facilitada utiliza proteínas canal o carrier para moléculas polares o iones","La ósmosis es el paso de agua a través de una membrana semipermeable hacia la zona más concentrada","El transporte activo consume ATP para mover solutos en contra de su gradiente de concentración","La bomba sodio-potasio saca tres iones sodio e introduce dos iones potasio por cada ATP consumido"]'),
('biologia', 'bachillerato', '{1}', '["Las células procariotas carecen de núcleo definido y su ADN circular está en el nucleoide","Poseen ribosomas 70S más pequeños que los 80S de las células eucariotas","Su membrana plasmática puede tener mesosomas que participan en la respiración celular","Muchas bacterias tienen pared celular de peptidoglucano que les confiere rigidez","Algunas presentan flagelos para la locomoción y pili para la conjugación bacteriana"]'),
('biologia', 'bachillerato', '{1}', '["El citoesqueleto está formado por microfilamentos, filamentos intermedios y microtúbulos","Los microfilamentos de actina participan en la contracción y el movimiento ameboide","Los filamentos intermedios dan resistencia mecánica a la célula frente a tensiones","Los microtúbulos de tubulina forman el huso mitótico y los centriolos","El citoesqueleto permite mantener la forma celular y el transporte intracelular de vesículas"]'),
('biologia', 'bachillerato', '{1}', '["La glucólisis ocurre en el citoplasma y es una ruta metabólica universal en los seres vivos","Consta de una fase de inversión energética que consume 2 ATP por molécula de glucosa","En la fase de rendimiento se generan 4 ATP y 2 NADH por glucosa","El balance neto de la glucólisis es de 2 ATP, 2 NADH y 2 piruvatos","El piruvato puede seguir la vía aeróbica en la mitocondria o la fermentación en el citoplasma"]'),
('biologia', 'bachillerato', '{1}', '["Las vacuolas de la célula vegetal ocupan gran parte del volumen celular","Almacenan agua, sales minerales, pigmentos y sustancias de reserva o desecho","La presión de turgencia generada por la vacuola mantiene la rigidez de la célula","Cuando la célula pierde agua la vacuola se contrae y se produce la plasmólisis","La recuperación del agua restaura la turgencia y la forma normal de la célula vegetal"]'),
('biologia', 'bachillerato', '{1}', '["El ciclo de Calvin comienza cuando la RuBisCO fija el CO2 uniéndolo a la ribulosa bifosfato","Se forman dos moléculas de ácido fosfoglicérico de tres carbonos cada una","El ácido fosfoglicérico se reduce usando ATP y NADPH de la fase luminosa","Se obtiene gliceraldehído-3-fosfato, del cual una parte se usa para sintetizar glucosa","El resto del G3P se recicla para regenerar la ribulosa bifosfato y reiniciar el ciclo"]'),
('biologia', 'bachillerato', '{1}', '["Los aminoácidos se clasifican según la naturaleza química de su cadena lateral R","Los aminoácidos se unen mediante enlaces peptídicos formando cadenas polipeptídicas","La estructura primaria es la secuencia lineal de aminoácidos de la proteína","La estructura secundaria genera patrones como la hélice alfa y la lámina beta plegada","La estructura terciaria es el plegamiento tridimensional completo de la cadena polipeptídica"]'),
('biologia', 'bachillerato', '{1}', '["Los ácidos nucleicos están formados por nucleótidos unidos por enlaces fosfodiéster","El ADN contiene desoxirribosa y las bases adenina, timina, citosina y guanina","El ARN contiene ribosa y sustituye la timina por uracilo como base nitrogenada","El ADN forma una doble hélice antiparalela estabilizada por puentes de hidrógeno entre bases","El apareamiento específico A-T y C-G permite la replicación semiconservativa del ADN"]'),
('biologia', 'bachillerato', '{1}', '["Los lípidos saponificables contienen ácidos grasos unidos a un alcohol por enlace éster","Los fosfolípidos tienen dos ácidos grasos y un grupo fosfato formando una molécula anfipática","En medio acuoso los fosfolípidos se organizan espontáneamente en bicapas lipídicas","Esta propiedad les permite formar las membranas biológicas de todas las células","Los lípidos insaponificables como el colesterol y las hormonas esteroideas carecen de ácidos grasos"]'),
('biologia', 'bachillerato', '{1}', '["Los monosacáridos como la glucosa son los glúcidos más simples con fórmula general CnH2nOn","Dos monosacáridos se unen mediante un enlace O-glucosídico formando un disacárido","La sacarosa es un disacárido formado por glucosa y fructosa unidos por enlace alfa","Los polisacáridos como el almidón almacenan energía en cadenas de glucosa ramificadas","La celulosa es un polisacárido estructural con enlaces beta que los humanos no pueden digerir"]'),
('biologia', 'bachillerato', '{1}', '["La cadena de transporte de electrones está ubicada en la membrana interna mitocondrial","El NADH dona electrones al complejo I que los transfiere a la ubiquinona","Los electrones pasan sucesivamente por los complejos III y IV bombeando protones","El oxígeno molecular actúa como aceptor final de electrones formando agua","La ATP sintasa utiliza el flujo de retorno de protones para fosforilar ADP a ATP"]'),
('biologia', 'bachillerato', '{1}', '["Las enzimas presentan una alta especificidad por su sustrato según el modelo llave-cerradura","El modelo del ajuste inducido propone que el centro activo se adapta al sustrato","La velocidad enzimática aumenta con la concentración de sustrato hasta alcanzar la Vmax","La constante de Michaelis-Menten indica la afinidad de la enzima por su sustrato","Los inhibidores competitivos ocupan el centro activo compitiendo con el sustrato por la unión"]'),
('biologia', 'bachillerato', '{1}', '["El agua es una molécula polar formada por un átomo de oxígeno y dos de hidrógeno","Los puentes de hidrógeno entre moléculas de agua le confieren alta cohesión molecular","Esta cohesión explica su elevada tensión superficial y su alto calor específico","El agua es el disolvente universal para las reacciones bioquímicas de los seres vivos","Su densidad máxima a 4 grados centígrados permite que el hielo flote protegiendo la vida acuática"]'),
('biologia', 'bachillerato', '{1}', '["El centrosoma se duplica durante la fase S generando dos centrosomas con sus centriolos","Al inicio de la profase los centrosomas migran hacia los polos opuestos de la célula","Los microtúbulos del huso mitótico se extienden desde los centrosomas hacia los cromosomas","Los cinetocoros de cada cromátida se unen a los microtúbulos del huso","En la anafase los microtúbulos se acortan arrastrando las cromátidas hacia los polos"]'),
('biologia', 'bachillerato', '{1}', '["La pared celular vegetal se forma a partir de la placa celular durante la citocinesis","La pared primaria está compuesta principalmente por celulosa, hemicelulosa y pectinas","Entre células adyacentes se encuentra la lámina media formada por pectatos de calcio","La pared secundaria se deposita internamente y contiene lignina en los tejidos leñosos","Los plasmodesmos atraviesan las paredes permitiendo la comunicación entre células vecinas"]'),
('biologia', 'bachillerato', '{1}', '["La fotosíntesis oxigénica ocurre en los cloroplastos de las células vegetales y las algas","El fotosistema II absorbe luz y oxida el agua liberando oxígeno, protones y electrones","Los electrones viajan por la cadena de transporte hasta el fotosistema I","El fotosistema I vuelve a excitar los electrones que reducen el NADP+ a NADPH","El gradiente de protones generado impulsa la síntesis de ATP por fotofosforilación"]'),
('biologia', 'bachillerato', '{1}', '["La gametogénesis masculina produce espermatozoides mediante espermatogénesis en los testículos","Las espermatogonias se dividen por mitosis y luego entran en meiosis formando espermatocitos","La meiosis genera cuatro espermátidas haploides a partir de cada espermatocito primario","Las espermátidas maduran en espermatozoides con cabeza, pieza media y flagelo","La espermatogénesis es un proceso continuo desde la pubertad hasta la vejez"]'),
('biologia', 'bachillerato', '{1}', '["La ovogénesis comienza en el desarrollo fetal con la formación de los ovocitos primarios","Los ovocitos primarios quedan detenidos en la profase I de la meiosis hasta la pubertad","En cada ciclo menstrual un ovocito completa la meiosis I generando un ovocito secundario","El ovocito secundario se libera en la ovulación y completa la meiosis II solo si es fecundado","A diferencia de la espermatogénesis, la ovogénesis produce un solo óvulo funcional por cada ciclo"]'),
('biologia', 'bachillerato', '{1}', '["El retículo endoplasmático liso carece de ribosomas en su superficie","Participa en la síntesis de lípidos como fosfolípidos y esteroides","En las células hepáticas interviene en la detoxificación de sustancias nocivas","En las células musculares almacena calcio necesario para la contracción","Su superficie lisa se diferencia claramente del retículo rugoso al microscopio electrónico"]'),
('biologia', 'bachillerato', '{1}', '["Los peroxisomas contienen enzimas oxidasas que producen peróxido de hidrógeno","La catalasa descompone el peróxido de hidrógeno en agua y oxígeno dentro del peroxisoma","Estas reacciones permiten detoxificar sustancias nocivas como el etanol","Los peroxisomas también participan en la beta-oxidación de ácidos grasos de cadena muy larga","Se originan por división de peroxisomas preexistentes o por gemación del retículo endoplasmático"]'),
('biologia', 'bachillerato', '{1}', '["La endocitosis mediada por receptor comienza con la unión del ligando a un receptor de membrana","Los receptores se concentran en invaginaciones recubiertas de clatrina","La membrana se invagina formando una vesícula recubierta que se internaliza","La cubierta de clatrina se desprende y la vesícula se fusiona con un endosoma temprano","El contenido se dirige a lisosomas para su degradación o se recicla a la membrana plasmática"]'),
('biologia', 'bachillerato', '{1}', '["La contracción muscular comienza con un impulso nervioso que llega a la placa motora","Se libera acetilcolina que despolariza la membrana de la fibra muscular","El calcio sale del retículo sarcoplásmico y se une a la troponina del filamento delgado","La tropomiosina se desplaza exponiendo los sitios de unión de actina para la miosina","Las cabezas de miosina se unen a la actina y tiran de ella acortando el sarcómero"]'),
('biologia', 'bachillerato', '{1}', '["Los genes homeóticos controlan el desarrollo embrionario determinando la identidad de cada segmento","Contienen una secuencia conservada llamada homeobox que codifica el homeodominio","El homeodominio es un factor de transcripción que se une al ADN regulando otros genes","Las mutaciones en genes homeóticos pueden provocar transformaciones homeóticas entre segmentos","Estos genes se organizan en el cromosoma en el mismo orden que los segmentos corporales que controlan"]'),
('biologia', 'bachillerato', '{1}', '["La fotosíntesis C4 es una adaptación de plantas tropicales para evitar la fotorrespiración","La enzima PEP carboxilasa fija el CO2 en ácido oxalacético en las células del mesófilo","El oxalacetato se convierte en malato que se transporta a las células de la vaina del haz","En la vaina se libera el CO2 que es fijado nuevamente por la RuBisCO en el ciclo de Calvin","Esta concentración de CO2 evita que la RuBisCO actúe como oxigenasa aumentando la eficiencia"]'),
('biologia', 'bachillerato', '{1}', '["El potencial de acción se inicia cuando un estímulo despolariza la membrana neuronal","Los canales de sodio dependientes de voltaje se abren permitiendo la entrada masiva de sodio","La membrana alcanza un potencial positivo de unos más cuarenta milivoltios en la fase de despolarización","Los canales de sodio se inactivan y se abren los de potasio produciendo la repolarización","La bomba sodio-potasio restaura las concentraciones iónicas iniciales durante el periodo refractario"]'),
('biologia', 'bachillerato', '{1}', '["Las sales minerales disueltas en el medio interno forman sistemas tampón o buffer","Los tampones mantienen el pH constante neutralizando los excesos de ácido o base","El sistema bicarbonato-ácido carbónico es el principal tampón del plasma sanguíneo","Si aumenta la concentración de protones el bicarbonato los neutraliza formando ácido carbónico","El ácido carbónico se descompone en agua y CO2 que se elimina por la respiración pulmonar"]'),
('biologia', 'bachillerato', '{1}', '["El aparato de Golgi está formado por dictiosomas compuestos de cisternas aplanadas y apiladas","La cara cis del Golgi recibe vesículas procedentes del retículo endoplasmático","Las proteínas y lípidos se modifican progresivamente al pasar por las cisternas mediales","En la cara trans se clasifican y empaquetan los productos en vesículas de destino específico","Las vesículas pueden dirigirse a la membrana plasmática, los lisosomas o las vacuolas de secreción"]'),
('biologia', 'bachillerato', '{1}', '["Las células madre totipotentes pueden originar cualquier tipo celular incluidos los tejidos extraembrionarios","Las células madre pluripotentes dan lugar a los tres linajes embrionarios pero no a la placenta","Las células madre multipotentes se diferencian en varios tipos celulares de un mismo tejido","Las células madre unipotentes solo pueden generar un tipo celular específico","La diferenciación celular implica la activación selectiva de genes según señales del entorno"]'),
('biologia', 'bachillerato', '{1}', '["El impulso nervioso llega al terminal sináptico del axón presináptico","Las vesículas sinápticas se fusionan con la membrana liberando neurotransmisores a la hendidura","Los neurotransmisores se unen a receptores específicos de la membrana postsináptica","Se produce un potencial postsináptico que puede ser excitador o inhibidor","Las enzimas degradan el neurotransmisor o se recapta para finalizar la señal sináptica"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('biologia', 'bachillerato', '{2}', '["Se aísla el ADN molde que contiene la secuencia que se desea amplificar","Se calienta a 95 grados para desnaturalizar la doble hélice separando las hebras","Los cebadores específicos se unen a las hebras complementarias al bajar a 55 grados","La Taq polimerasa sintetiza nuevas cadenas a 72 grados a partir de los cebadores","Tras 30 ciclos se obtienen millones de copias del fragmento de ADN de interés"]'),
('biologia', 'bachillerato', '{2}', '["El sistema CRISPR-Cas9 utiliza un ARN guía complementario a la secuencia diana del ADN","El ARN guía dirige la proteína Cas9 hasta el punto exacto del genoma a editar","La nucleasa Cas9 corta ambas hebras del ADN en el sitio especificado por el ARN guía","La célula repara el corte pudiendo introducir inserciones o deleciones que inactivan el gen","Alternativamente se puede insertar una secuencia correcta usando un molde de reparación"]'),
('biologia', 'bachillerato', '{2}', '["Un antígeno extraño entra en el organismo y es capturado por una célula presentadora","La célula presentadora procesa el antígeno y lo expone en su superficie con el MHC-II","Los linfocitos T helper reconocen el complejo antígeno-MHC-II y se activan","Los T helper liberan citoquinas que estimulan a los linfocitos B y T citotóxicos","Los linfocitos B producen anticuerpos y los T citotóxicos destruyen las células infectadas"]'),
('biologia', 'bachillerato', '{2}', '["Se cruzan dos individuos heterocigotos Aa para un carácter con dominancia completa","Los gametos posibles son A y a para cada progenitor según la primera ley de Mendel","El cuadro de Punnett muestra las combinaciones: AA, Aa, aA y aa","La proporción genotípica esperada en la F2 es 1 AA, 2 Aa y 1 aa","La proporción fenotípica resulta ser 3 dominantes por cada 1 recesivo"]'),
('biologia', 'bachillerato', '{2}', '["Se plantea un cruzamiento dihíbrido entre individuos AaBb para dos caracteres independientes","Cada progenitor produce cuatro tipos de gametos: AB, Ab, aB y ab","Se construye un cuadro de Punnett de 4x4 con las 16 combinaciones posibles","Las proporciones fenotípicas esperadas son 9:3:3:1 según la segunda ley de Mendel","Los caracteres se transmiten independientemente porque los genes están en cromosomas distintos"]'),
('biologia', 'bachillerato', '{2}', '["Un virus bacteriófago se adhiere a la superficie de la bacteria hospedadora","Inyecta su ácido nucleico en el interior de la célula bacteriana","El ADN viral utiliza la maquinaria de la bacteria para replicarse y sintetizar proteínas virales","Se ensamblan las nuevas partículas virales completas dentro del citoplasma bacteriano","La bacteria se lisa liberando cientos de nuevos fagos que infectarán otras bacterias"]'),
('biologia', 'bachillerato', '{2}', '["Una vacuna contiene antígenos atenuados o inactivados del patógeno causante de la enfermedad","Los antígenos son reconocidos por el sistema inmunitario sin provocar la enfermedad","Los linfocitos B se activan y producen anticuerpos específicos contra esos antígenos","Se generan células de memoria B y T que permanecen en el organismo durante años","Ante una infección real la respuesta secundaria es más rápida e intensa gracias a la memoria inmune"]'),
('biologia', 'bachillerato', '{2}', '["La electroforesis en gel de agarosa separa fragmentos de ADN según su tamaño","Se prepara el gel y se carga la muestra de ADN digerido con enzimas de restricción","Se aplica un campo eléctrico que hace migrar los fragmentos negativos hacia el polo positivo","Los fragmentos más pequeños avanzan más rápido a través de los poros del gel","Se tiñe el gel con bromuro de etidio y se visualizan las bandas bajo luz ultravioleta"]'),
('biologia', 'bachillerato', '{2}', '["Un retrovirus como el VIH entra en la célula humana fusionándose con su membrana","La transcriptasa inversa convierte el ARN viral en ADN de doble cadena","La integrasa inserta el ADN viral en el genoma de la célula hospedadora","La célula transcribe y traduce los genes virales produciendo nuevas proteínas del virus","Los nuevos viriones se ensamblan y salen por gemación infectando más células del sistema inmune"]'),
('biologia', 'bachillerato', '{2}', '["Los organismos productores fijan la energía solar en materia orgánica mediante la fotosíntesis","Los consumidores primarios o herbívoros se alimentan de los productores","Los consumidores secundarios o carnívoros se alimentan de los herbívoros","En cada nivel trófico se pierde aproximadamente un 90 por ciento de la energía como calor","Los descomponedores reciclan la materia orgánica devolviendo los nutrientes al suelo"]'),
('biologia', 'bachillerato', '{2}', '["La herencia ligada al sexo se refiere a genes localizados en el cromosoma X","Una mujer portadora XᴬXᵃ no manifiesta la enfermedad pero transmite el alelo recesivo","Si cruza con un varón sano XᴬY, la mitad de los hijos varones pueden ser afectados","Las hijas tienen un 50 por ciento de probabilidad de ser portadoras como la madre","La hemofilia y el daltonismo son ejemplos clásicos de herencia ligada al cromosoma X"]'),
('biologia', 'bachillerato', '{2}', '["Las bacterias Gram positivas tienen una gruesa pared de peptidoglucano que retiene el cristal violeta","En la tinción de Gram se tiñen primero con cristal violeta y luego con lugol","Se aplica alcohol-acetona como decolorante que no penetra la gruesa pared de las Gram positivas","Las Gram negativas pierden el cristal violeta al tener una capa fina de peptidoglucano","Se aplica safranina como colorante de contraste tiñendo de rosa las bacterias Gram negativas"]'),
('biologia', 'bachillerato', '{2}', '["La sucesión ecológica primaria comienza en un sustrato sin vida como roca desnuda o lava","Los organismos pioneros como los líquenes colonizan el sustrato y lo meteorizan","Se forma un suelo incipiente que permite la instalación de musgos y herbáceas","Gradualmente llegan arbustos y árboles que aumentan la complejidad del ecosistema","La comunidad alcanza el clímax cuando se establece un equilibrio estable con máxima biodiversidad"]'),
('biologia', 'bachillerato', '{2}', '["La clonación reproductiva comienza extrayendo el núcleo de una célula somática del organismo donante","Se obtiene un ovocito de una hembra y se le extrae su propio núcleo enucleándolo","El núcleo de la célula somática se transfiere al ovocito enucleado mediante microinyección","Se estimula eléctricamente el ovocito para que comience a dividirse como un embrión normal","El embrión se implanta en una madre de alquiler que gestará un clon genético del donante"]'),
('biologia', 'bachillerato', '{2}', '["Las mutaciones génicas alteran la secuencia de nucleótidos de un gen concreto","Las sustituciones cambian un nucleótido por otro pudiendo ser transiciones o transversiones","Las inserciones o deleciones de nucleótidos provocan un cambio en el marco de lectura","Muchas mutaciones son silenciosas gracias a la degeneración del código genético","Las mutaciones con sentido erróneo cambian un aminoácido y pueden alterar la función de la proteína"]'),
('biologia', 'bachillerato', '{2}', '["La regulación génica en procariotas se explica con el modelo del operón lac de Jacob y Monod","En ausencia de lactosa el represor se une al operador bloqueando la transcripción","Cuando hay lactosa, la alolactosa se une al represor cambiando su conformación","El represor modificado se separa del operador permitiendo que la ARN polimerasa transcriba","Se sintetizan las enzimas beta-galactosidasa, permeasa y transacetilasa para metabolizar la lactosa"]'),
('biologia', 'bachillerato', '{2}', '["Los anticuerpos o inmunoglobulinas tienen estructura en forma de Y con dos cadenas pesadas y dos ligeras","Las regiones variables de cada brazo de la Y forman el sitio de unión al antígeno o paratopo","Cada anticuerpo reconoce un epítopo específico del antígeno con alta afinidad","Los anticuerpos pueden neutralizar patógenos, opsonizarlos o activar el sistema del complemento","Las cinco clases de inmunoglobulinas (IgG, IgM, IgA, IgD, IgE) tienen funciones diferentes en la defensa"]'),
('biologia', 'bachillerato', '{2}', '["Los organismos transgénicos contienen genes de otra especie insertados en su genoma","Se identifica el gen de interés y se aísla mediante enzimas de restricción","El gen se introduce en un vector de expresión con un promotor adecuado","El vector se transfiere al organismo receptor mediante transformación, microinyección o biobalística","El organismo transgénico expresa el nuevo gen produciendo la proteína de interés"]'),
('biologia', 'bachillerato', '{2}', '["El ciclo del nitrógeno comienza con la fijación del N2 atmosférico por bacterias nitrificantes","Las bacterias fijadoras convierten el nitrógeno gaseoso en amonio asimilable","Las bacterias nitrificantes oxidan el amonio a nitrito y luego a nitrato en el suelo","Las plantas absorben los nitratos por las raíces y los incorporan a aminoácidos y proteínas","Las bacterias desnitrificantes devuelven el nitrógeno al aire cerrando el ciclo biogeoquímico"]'),
('biologia', 'bachillerato', '{2}', '["La respuesta inflamatoria se inicia cuando los tejidos sufren una lesión o infección","Los mastocitos liberan histamina que produce vasodilatación y aumento de la permeabilidad capilar","Los neutrófilos migran al foco de infección por quimiotaxis y fagocitan los patógenos","Los macrófagos llegan después reforzando la fagocitosis y presentando antígenos","La zona afectada muestra los signos clásicos de calor, rubor, tumor y dolor"]'),
('biologia', 'bachillerato', '{2}', '["La reacción en cadena de la polimerasa cuantitativa o PCR en tiempo real permite cuantificar el ADN","Se añade un fluoróforo que emite luz proporcionalmente a la cantidad de producto amplificado","En cada ciclo se mide la fluorescencia y se genera una curva de amplificación","El ciclo umbral Ct indica el momento en que la señal supera el nivel basal de fluorescencia","Comparando los Ct con una curva patrón se calcula la cantidad inicial de ADN de la muestra"]'),
('biologia', 'bachillerato', '{2}', '["Las enfermedades autoinmunes se producen cuando el sistema inmune ataca tejidos propios","La tolerancia inmunológica se pierde y los linfocitos reconocen antígenos propios como extraños","Se producen autoanticuerpos que dañan células y tejidos del propio organismo","Enfermedades como el lupus o la artritis reumatoide son ejemplos de autoinmunidad","El tratamiento suele incluir inmunosupresores que reducen la actividad del sistema inmune"]'),
('biologia', 'bachillerato', '{2}', '["La selección natural actúa sobre la variabilidad genética de las poblaciones","Los individuos con caracteres más favorables tienen mayor éxito reproductivo","Estos caracteres ventajosos se transmiten con mayor frecuencia a la descendencia","Con el paso de las generaciones cambian las frecuencias alélicas de la población","La acumulación de cambios puede dar lugar a la especiación si hay aislamiento reproductivo"]'),
('biologia', 'bachillerato', '{2}', '["Las células cancerosas acumulan mutaciones en protooncogenes y genes supresores de tumores","Los protooncogenes mutados se convierten en oncogenes que estimulan la proliferación descontrolada","Los genes supresores como p53 pierden su función y no detienen el ciclo celular alterado","Las células tumorales evaden la apoptosis y se dividen indefinidamente formando un tumor","La angiogénesis y la metástasis permiten al tumor crecer y diseminarse a otros órganos"]'),
('biologia', 'bachillerato', '{2}', '["Los marcadores genéticos polimórficos se utilizan en la huella genética o DNA fingerprinting","Se extrae el ADN de la muestra biológica y se digiere con enzimas de restricción","Los fragmentos se separan por electroforesis generando un patrón de bandas único","Se compara el patrón de bandas de la muestra con el de los sospechosos o familiares","La probabilidad de que dos personas no emparentadas compartan el mismo patrón es extremadamente baja"]'),
('biologia', 'bachillerato', '{2}', '["La terapia génica busca corregir enfermedades genéticas introduciendo copias funcionales del gen alterado","Se selecciona un vector viral seguro como un adenovirus o un lentivirus modificado","El gen terapéutico se inserta en el vector que lo transportará a las células del paciente","Las células del paciente se infectan con el vector e incorporan el gen funcional a su genoma","La expresión del gen correcto permite producir la proteína que faltaba o estaba defectuosa"]'),
('biologia', 'bachillerato', '{2}', '["Un cruzamiento prueba cruza un individuo de fenotipo dominante con un homocigoto recesivo","Si toda la descendencia muestra fenotipo dominante el individuo probado es homocigoto dominante","Si aparecen individuos con fenotipo recesivo el individuo probado es heterocigoto","La proporción 1:1 en la descendencia confirma que el progenitor dominante era Aa","El cruzamiento prueba permite deducir el genotipo de individuos con fenotipo dominante"]'),
('biologia', 'bachillerato', '{2}', '["La codominancia se observa cuando ambos alelos se expresan simultáneamente en el heterocigoto","Los grupos sanguíneos ABO son un ejemplo con los alelos IA, IB e i","Un individuo IAIB expresa ambos antígenos A y B en la superficie de sus eritrocitos","El alelo i es recesivo respecto a IA e IB, por lo que el grupo O requiere genotipo ii","Las transfusiones deben respetar la compatibilidad de antígenos para evitar reacciones hemolíticas"]'),
('biologia', 'bachillerato', '{2}', '["El sistema del complemento es un conjunto de proteínas plasmáticas de la inmunidad innata","La vía clásica se activa cuando el anticuerpo unido al antígeno activa la proteína C1","Una cascada de activación proteolítica amplifica la señal sucesivamente","Las proteínas del complemento perforan la membrana del patógeno formando el complejo de ataque","Además, los fragmentos liberados actúan como opsoninas y quimiotácticos potenciando la fagocitosis"]'),
('biologia', 'bachillerato', '{2}', '["Los interferones son citoquinas producidas por células infectadas por virus","Se liberan al medio extracelular y se unen a receptores de células vecinas no infectadas","Las células vecinas activan genes que producen proteínas antivirales bloqueando la replicación viral","Los interferones también activan las células NK que destruyen células infectadas","Su acción es inespecífica ya que protegen contra cualquier tipo de virus no solo el inductor"]'),
('biologia', 'bachillerato', '{2}', '["La epistasis se produce cuando un gen enmascara la expresión de otro gen no alélico","En el color del pelaje de ratones el gen C permite la deposición de pigmento","Si el ratón es homocigoto recesivo cc no se deposita pigmento y resulta albino","Independientemente del genotipo en el locus B el ratón cc será siempre blanco","La proporción fenotípica en un dihíbrido epistático se desvía de la esperada 9:3:3:1"]'),
('biologia', 'bachillerato', '{2}', '["La eutrofización de un lago comienza con el vertido excesivo de nutrientes como nitratos y fosfatos","Los nutrientes estimulan el crecimiento masivo de algas en la superficie del agua","Las algas impiden el paso de la luz y las plantas acuáticas del fondo mueren","Las bacterias aerobias descomponen la materia orgánica muerta consumiendo el oxígeno disuelto","La anoxia provoca la muerte de peces y otros organismos convirtiendo el lago en un medio inhóspito"]'),
('biologia', 'bachillerato', '{2}', '["Los plásmidos son moléculas de ADN circular extracromosómico presentes en muchas bacterias","Los plásmidos de resistencia o plásmidos R portan genes que confieren resistencia a antibióticos","La conjugación bacteriana transfiere plásmidos de una bacteria donadora a una receptora","La bacteria receptora adquiere los genes de resistencia y se vuelve resistente al antibiótico","El uso excesivo de antibióticos selecciona bacterias resistentes agravando el problema de la multirresistencia"]'),
('biologia', 'bachillerato', '{2}', '["Los linfocitos T se desarrollan en el timo donde sufren selección positiva y negativa","La selección positiva permite sobrevivir solo a los linfocitos que reconocen el MHC propio","La selección negativa elimina los linfocitos que reaccionan fuertemente contra antígenos propios","Los linfocitos maduros salen del timo como T helper CD4 o T citotóxicos CD8","Este proceso asegura la tolerancia inmunológica evitando respuestas autoinmunes"]'),
('biologia', 'bachillerato', '{2}', '["La biotecnología alimentaria utiliza microorganismos para producir alimentos fermentados","Las bacterias lácticas como Lactobacillus transforman la lactosa de la leche en ácido láctico","El descenso del pH coagula las proteínas de la leche produciendo yogur o queso","Las levaduras del género Saccharomyces fermentan los azúcares del mosto produciendo vino","El control de las condiciones de fermentación determina las características del producto final"]'),
('biologia', 'bachillerato', '{2}', '["La especiación alopátrica comienza cuando una barrera geográfica divide una población","Las dos subpoblaciones aisladas acumulan mutaciones diferentes de forma independiente","La selección natural y la deriva genética actúan de forma distinta en cada subpoblación","Con el tiempo las diferencias genéticas se acumulan produciendo aislamiento reproductivo","Si las poblaciones vuelven a encontrarse ya no pueden cruzarse y se consideran especies distintas"]'),
('biologia', 'bachillerato', '{2}', '["La ingeniería genética permite producir insulina humana recombinante en bacterias","Se aísla el gen de la insulina humana o se sintetiza a partir de la secuencia conocida","El gen se inserta en un plásmido de expresión con un promotor bacteriano fuerte","El plásmido recombinante se introduce en Escherichia coli por transformación","La bacteria expresa y produce insulina humana que se purifica para uso terapéutico en diabéticos"]'),
('biologia', 'bachillerato', '{2}', '["El efecto invernadero natural mantiene la temperatura media de la Tierra en unos 15 grados","La quema de combustibles fósiles aumenta la concentración de CO2 y otros gases invernadero","El exceso de gases atrapa más radiación infrarroja elevando la temperatura global","El calentamiento global provoca deshielo de los casquetes polares y subida del nivel del mar","Las alteraciones climáticas afectan a los ecosistemas provocando pérdida de biodiversidad y migraciones"]'),
('biologia', 'bachillerato', '{2}', '["La apoptosis o muerte celular programada es un proceso genéticamente controlado","Señales internas o externas activan las caspasas iniciadoras que desencadenan la cascada apoptótica","Las caspasas ejecutoras degradan las proteínas estructurales y fragmentan el ADN nuclear","La célula se encoge y forma cuerpos apoptóticos rodeados de membrana","Los macrófagos fagocitan los cuerpos apoptóticos sin generar respuesta inflamatoria"]'),
('biologia', 'bachillerato', '{2}', '["El Southern blot es una técnica para detectar secuencias específicas de ADN en una muestra","Se digiere el ADN con enzimas de restricción y se separan los fragmentos por electroforesis","Los fragmentos se transfieren a una membrana de nylon por capilaridad","Se añade una sonda de ADN marcada complementaria a la secuencia buscada","La sonda se hibrida con su secuencia complementaria y se detecta por autorradiografía o fluorescencia"]'),
('biologia', 'bachillerato', '{2}', '["El ciclo lítico de un virus comienza con la adsorción del virión a la célula hospedadora","El ácido nucleico viral penetra en la célula y se replica utilizando la maquinaria celular","Se transcriben y traducen los genes virales produciendo proteínas estructurales y funcionales","Los componentes virales se ensamblan formando nuevos viriones completos en el citoplasma","La célula hospedadora se lisa liberando los nuevos virus que infectarán otras células"]'),
('biologia', 'bachillerato', '{2}', '["El ciclo lisogénico comienza igual que el lítico con la infección del virus a la bacteria","El ADN viral se integra en el cromosoma bacteriano formando un profago","El profago se replica junto con el ADN bacteriano cada vez que la bacteria se divide","Las bacterias lisogénicas pueden mantener el profago integrado durante muchas generaciones","Ante un estímulo como la radiación UV el profago se escinde e inicia un ciclo lítico"]'),
('biologia', 'bachillerato', '{2}', '["La herencia poligénica implica que un carácter está controlado por múltiples genes","Cada gen aporta un pequeño efecto aditivo al fenotipo resultante","La estatura humana depende de cientos de genes además de factores ambientales","La distribución de los fenotipos en la población sigue una curva normal o campana de Gauss","Esta variación continua dificulta la clasificación en categorías discretas como en la herencia mendeliana"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('fisica', 'bachillerato', '{1}', '["Se lanza un proyectil con velocidad inicial formando un ángulo con la horizontal","La componente horizontal de la velocidad se mantiene constante durante todo el vuelo","La componente vertical disminuye en la subida y aumenta en la bajada por efecto de la gravedad","El proyectil describe una parábola alcanzando la altura máxima cuando la velocidad vertical es cero","El alcance máximo se consigue con un ángulo de lanzamiento de 45 grados en ausencia de rozamiento"]'),
('fisica', 'bachillerato', '{1}', '["Un cuerpo parte del reposo y se acelera uniformemente a 3 metros por segundo cuadrado","Tras 4 segundos alcanza una velocidad de 12 metros por segundo","La distancia recorrida se calcula con la fórmula x = medio por a por t al cuadrado","El espacio total recorrido en esos 4 segundos es de 24 metros","Representamos la gráfica v-t como una recta ascendente cuya pendiente es la aceleración"]'),
('fisica', 'bachillerato', '{1}', '["Un coche circula a velocidad constante y el conductor frena bruscamente","La fuerza de rozamiento entre los neumáticos y la carretera decelera el vehículo","Usando la segunda ley de Newton calculamos la deceleración a partir de la fuerza y la masa","La distancia de frenado se calcula igualando la energía cinética al trabajo de la fuerza de rozamiento","A mayor velocidad inicial la distancia de frenado aumenta con el cuadrado de la velocidad"]'),
('fisica', 'bachillerato', '{1}', '["Un bloque se encuentra sobre un plano inclinado sin rozamiento","Descomponemos el peso en una componente paralela al plano y otra perpendicular","La componente perpendicular es equilibrada por la fuerza normal del plano","La componente paralela es la fuerza neta que acelera el bloque cuesta abajo","La aceleración del bloque es g por el seno del ángulo de inclinación del plano"]'),
('fisica', 'bachillerato', '{1}', '["Dos cuerpos se atraen gravitatoriamente según la ley de Newton de gravitación universal","La fuerza es proporcional al producto de las masas e inversamente proporcional al cuadrado de la distancia","Para calcular la aceleración gravitatoria en la superficie de la Tierra usamos g = GM/R²","La constante G se midió por primera vez en el experimento de la balanza de torsión de Cavendish","La gravedad de la Tierra varía ligeramente según la latitud y la altitud del punto considerado"]'),
('fisica', 'bachillerato', '{1}', '["Un gas ideal se encuentra en un recipiente cerrado a temperatura y presión iniciales conocidas","Se calienta el gas manteniendo el volumen constante en un proceso isocórico","La presión del gas aumenta proporcionalmente a la temperatura absoluta según la ley de Gay-Lussac","El calor absorbido por el gas se calcula con Q = n por Cv por el incremento de temperatura","Como el volumen no cambia, todo el calor se convierte en energía interna del gas"]'),
('fisica', 'bachillerato', '{1}', '["Un gas se expande isotérmicamente empujando un pistón dentro de un cilindro","La temperatura permanece constante y la energía interna del gas ideal no varía","El trabajo realizado por el gas se calcula como el área bajo la curva en el diagrama P-V","Según la primera ley de la termodinámica todo el calor absorbido se convierte en trabajo","La presión disminuye hiperbólicamente según la ley de Boyle: P por V es constante"]'),
('fisica', 'bachillerato', '{1}', '["Un gas realiza un proceso adiabático en el que no intercambia calor con el entorno","La expansión adiabática hace que el gas se enfríe al realizar trabajo sin aporte externo de calor","La relación entre presión y volumen sigue la ecuación P por V elevado a gamma es constante","Gamma es el cociente Cp/Cv que depende del tipo de gas monoatómico, diatómico o poliatómico","La curva adiabática en el diagrama P-V es más pronunciada que la isoterma"]'),
('fisica', 'bachillerato', '{1}', '["Un péndulo simple se desplaza de su posición de equilibrio un ángulo pequeño","La fuerza restauradora es la componente tangencial del peso proporcional al desplazamiento","El péndulo oscila con movimiento armónico simple cuyo periodo es T = 2π√(L/g)","El periodo depende solo de la longitud del hilo y de la gravedad, no de la masa ni la amplitud","La energía total se conserva alternándose entre cinética en el punto más bajo y potencial en los extremos"]'),
('fisica', 'bachillerato', '{1}', '["Un cuerpo de 2 kg se mueve a 5 m/s y choca frontalmente con otro de 3 kg en reposo","Aplicamos la conservación del momento lineal: m1v1 + m2v2 = m1v1 prima + m2v2 prima","Si el choque es perfectamente elástico también se conserva la energía cinética","Resolvemos el sistema de ecuaciones para obtener las velocidades finales de ambos cuerpos","El cuerpo más ligero rebota y el más pesado sale hacia delante con menor velocidad"]'),
('fisica', 'bachillerato', '{1}', '["Se aplica una fuerza de 50 N a un muelle que se estira 0,1 metros desde su posición natural","La constante elástica del muelle es k = F/x = 500 N/m según la ley de Hooke","La energía potencial elástica almacenada es Ep = medio por k por x al cuadrado","Si se suelta el muelle, la energía potencial se transforma en energía cinética del objeto unido","La frecuencia de oscilación del sistema masa-muelle es f = (1/2π)√(k/m)"]'),
('fisica', 'bachillerato', '{1}', '["Una onda transversal se propaga por una cuerda tensa de izquierda a derecha","Cada punto de la cuerda oscila perpendicularmente a la dirección de propagación","La longitud de onda es la distancia entre dos crestas o dos valles consecutivos","La velocidad de propagación depende de la tensión de la cuerda y su densidad lineal","La frecuencia y la longitud de onda se relacionan mediante v = lambda por f"]'),
('fisica', 'bachillerato', '{1}', '["Dos fuentes emiten ondas coherentes de la misma frecuencia en un medio homogéneo","Cuando las ondas se encuentran en fase se produce interferencia constructiva y la amplitud se suma","Cuando se encuentran en contrafase se produce interferencia destructiva y la amplitud se anula","El patrón de interferencia depende de la diferencia de camino entre las dos ondas","La condición para un máximo es que la diferencia de camino sea un múltiplo entero de la longitud de onda"]'),
('fisica', 'bachillerato', '{1}', '["El rendimiento de una máquina térmica se define como el trabajo útil dividido entre el calor absorbido","Según el segundo principio de la termodinámica ninguna máquina puede tener rendimiento del 100 por ciento","La máquina de Carnot establece el rendimiento máximo teórico entre dos temperaturas","El rendimiento de Carnot es 1 menos Tf/Tc donde Tf y Tc son temperaturas en kelvin","Para aumentar el rendimiento se debe aumentar Tc o disminuir Tf"]'),
('fisica', 'bachillerato', '{1}', '["Un objeto se mueve en una trayectoria circular con velocidad constante en módulo","La dirección de la velocidad cambia continuamente siendo siempre tangente a la circunferencia","Existe una aceleración centrípeta dirigida hacia el centro de la trayectoria","La aceleración centrípeta se calcula como v al cuadrado dividido por el radio","La fuerza centrípeta necesaria puede ser la tensión de una cuerda, la gravedad o el rozamiento"]'),
('fisica', 'bachillerato', '{1}', '["La energía cinética de un cuerpo en movimiento es Ec = medio por m por v al cuadrado","Cuando se aplica una fuerza neta el trabajo realizado iguala el cambio de energía cinética","El teorema del trabajo y la energía cinética relaciona fuerza, desplazamiento y velocidad","Si la fuerza es conservativa el trabajo no depende del camino sino de las posiciones inicial y final","La energía mecánica total se conserva cuando solo actúan fuerzas conservativas"]'),
('fisica', 'bachillerato', '{1}', '["Un cuerpo se lanza horizontalmente desde un acantilado con velocidad v0","El movimiento horizontal es uniforme con velocidad constante v0","El movimiento vertical es de caída libre con aceleración g hacia abajo","El tiempo de caída depende solo de la altura del acantilado y no de la velocidad horizontal","La trayectoria resultante es una parábola y el punto de impacto se calcula combinando ambos movimientos"]'),
('fisica', 'bachillerato', '{1}', '["La presión hidrostática en un fluido aumenta con la profundidad según P = P0 + rho por g por h","Un cuerpo sumergido experimenta un empuje ascendente igual al peso del fluido desalojado","El principio de Arquímedes explica por qué los barcos flotan a pesar de estar hechos de acero","Si el empuje es mayor que el peso el cuerpo flota, si es menor el cuerpo se hunde","Un cuerpo en equilibrio flotando tiene sumergida la fracción de volumen igual a su densidad relativa"]'),
('fisica', 'bachillerato', '{1}', '["La entropía de un sistema aislado nunca disminuye según el segundo principio de la termodinámica","En un proceso reversible la entropía total del universo permanece constante","En un proceso irreversible la entropía total del universo siempre aumenta","El aumento de entropía se asocia con un incremento del desorden molecular del sistema","La muerte térmica del universo sería el estado de máxima entropía donde ya no son posibles más procesos"]'),
('fisica', 'bachillerato', '{1}', '["Un sistema de dos poleas reduce la fuerza necesaria para elevar una carga pesada","La ventaja mecánica de la polea móvil es 2 porque divide la tensión entre dos tramos de cuerda","Sin embargo la distancia que hay que tirar del cable se duplica para compensar","El trabajo total sigue siendo el mismo ya que W = F por d no cambia idealmente","En la práctica el rozamiento reduce ligeramente la eficiencia del sistema de poleas"]'),
('fisica', 'bachillerato', '{1}', '["La velocidad del sonido depende del medio de propagación y de la temperatura","En el aire a 20 grados centígrados el sonido viaja a aproximadamente 343 metros por segundo","En el agua la velocidad del sonido es unas cuatro veces mayor que en el aire","En los sólidos la velocidad es aún mayor debido a la mayor rigidez del medio","El sonido no puede propagarse en el vacío porque necesita un medio material para transmitirse"]'),
('fisica', 'bachillerato', '{1}', '["Se calienta un bloque de hielo a cero grados centígrados suministrándole calor de forma constante","El hielo absorbe calor latente de fusión manteniendo la temperatura en cero grados mientras funde","Una vez derretido todo el hielo el agua líquida comienza a elevar su temperatura","Al alcanzar los 100 grados centígrados el agua absorbe calor latente de vaporización","El vapor de agua continúa calentándose si se sigue suministrando calor por encima de los 100 grados"]'),
('fisica', 'bachillerato', '{1}', '["El momento de inercia de un cuerpo rígido depende de la distribución de masa respecto al eje de giro","Un disco sólido tiene menor momento de inercia que un aro de la misma masa y radio","El par de fuerzas o torque produce aceleración angular según tau = I por alfa","La conservación del momento angular explica por qué un patinador gira más rápido al recoger los brazos","La energía cinética de rotación es Ec = medio por I por omega al cuadrado"]'),
('fisica', 'bachillerato', '{1}', '["Conectamos varias resistencias en serie en un circuito eléctrico con una batería","La corriente que circula es la misma a través de todas las resistencias","La resistencia total del circuito es la suma de todas las resistencias individuales","El voltaje total se reparte entre las resistencias proporcionalmente a su valor","La potencia disipada en cada resistencia es P = I al cuadrado por R"]'),
('fisica', 'bachillerato', '{1}', '["Conectamos varias resistencias en paralelo entre dos nudos del circuito","El voltaje es el mismo en todas las resistencias conectadas en paralelo","La corriente total se divide entre las ramas de forma inversamente proporcional a cada resistencia","La resistencia equivalente del conjunto es menor que la menor de las resistencias individuales","Al añadir más resistencias en paralelo la resistencia total del circuito disminuye"]'),
('fisica', 'bachillerato', '{1}', '["Se aplica el principio de conservación de la energía a una montaña rusa sin rozamiento","En el punto más alto la energía potencial gravitatoria es máxima y la cinética es mínima","Al descender la energía potencial se convierte en energía cinética aumentando la velocidad","En el punto más bajo toda la energía es cinética y la velocidad alcanza su valor máximo","La velocidad en cualquier punto se calcula igualando la energía mecánica inicial y final"]'),
('fisica', 'bachillerato', '{1}', '["Un satélite en órbita geoestacionaria tarda exactamente 24 horas en completar una vuelta","La órbita geoestacionaria se sitúa a unos 36000 kilómetros de altitud sobre el ecuador","El satélite parece inmóvil desde la Tierra porque gira a la misma velocidad angular","Igualamos la fuerza gravitatoria con la fuerza centrípeta para calcular el radio orbital","Los satélites geoestacionarios se usan para telecomunicaciones y meteorología por su posición fija"]'),
('fisica', 'bachillerato', '{1}', '["La ley de gravitación universal establece que F = G por m1 por m2 entre r al cuadrado","El campo gravitatorio g en un punto es la fuerza por unidad de masa: g = GM/r²","La energía potencial gravitatoria es negativa y tiende a cero cuando la distancia tiende a infinito","La velocidad de escape es la velocidad mínima para que un cuerpo abandone el campo gravitatorio","Se calcula igualando la energía cinética a la energía potencial gravitatoria en la superficie"]'),
('fisica', 'bachillerato', '{1}', '["Un motor térmico de Carnot opera entre un foco caliente a 600 K y uno frío a 300 K","El rendimiento máximo teórico es 1 menos 300/600 que equivale al 50 por ciento","En cada ciclo absorbe 1000 julios del foco caliente y convierte 500 en trabajo útil","Los 500 julios restantes se ceden al foco frío como calor residual","Ningún motor real puede superar el rendimiento de Carnot operando entre las mismas temperaturas"]'),
('fisica', 'bachillerato', '{1}', '["El efecto Doppler se produce cuando la fuente sonora y el observador tienen movimiento relativo","Si la fuente se acerca al observador las ondas se comprimen y la frecuencia percibida aumenta","Si la fuente se aleja las ondas se estiran y la frecuencia percibida disminuye","La fórmula del efecto Doppler relaciona la frecuencia percibida con las velocidades de fuente y observador","Este efecto se utiliza en radares de velocidad y en ecografías médicas con ultrasonidos"]'),
('fisica', 'bachillerato', '{1}', '["Se define el trabajo de una fuerza constante como W = F por d por coseno del ángulo","Si la fuerza y el desplazamiento son perpendiculares el trabajo realizado es cero","La potencia es el trabajo realizado por unidad de tiempo medida en vatios","Una grúa que eleva una carga de 500 kg a 10 metros realiza un trabajo igual a mgh","Si tarda 5 segundos la potencia media desarrollada es de 9800 vatios"]'),
('fisica', 'bachillerato', '{1}', '["Un muelle horizontal conectado a un bloque se comprime y se suelta desde el reposo","La energía potencial elástica almacenada se transforma en energía cinética del bloque","El bloque alcanza la velocidad máxima al pasar por la posición de equilibrio del muelle","A partir de ahí el muelle se estira y el bloque desacelera convirtiendo cinética en potencial","El movimiento oscilatorio se repite indefinidamente si no hay fuerzas disipativas"]'),
('fisica', 'bachillerato', '{1}', '["Una onda estacionaria se forma por la superposición de dos ondas de igual frecuencia en sentidos opuestos","En los nodos la amplitud de oscilación es siempre cero y no hay movimiento","En los vientres la amplitud es máxima y los puntos oscilan con la mayor intensidad","La distancia entre dos nodos consecutivos es media longitud de onda","Las ondas estacionarias explican las frecuencias naturales de vibración en cuerdas y tubos sonoros"]'),
('fisica', 'bachillerato', '{1}', '["Un cuerpo está en equilibrio estático cuando la suma de fuerzas y de momentos es cero","Se identifican todas las fuerzas que actúan sobre el cuerpo dibujando el diagrama de cuerpo libre","Se elige un punto de referencia conveniente para calcular los momentos o torques","Se plantean las ecuaciones de equilibrio de fuerzas en X e Y y de momentos","Resolviendo el sistema se obtienen las fuerzas desconocidas como reacciones en los apoyos"]'),
('fisica', 'bachillerato', '{1}', '["La primera ley de la termodinámica establece que delta U = Q - W para un gas","Q es el calor intercambiado y W es el trabajo realizado por el gas","En un proceso a presión constante el trabajo es W = P por delta V","El calor a presión constante es Q = n por Cp por delta T","La diferencia entre Cp y Cv para un gas ideal es la constante R de los gases"]'),
('fisica', 'bachillerato', '{1}', '["Dos cuerpos de masas m1 y m2 se unen con una cuerda que pasa por una polea sin rozamiento","La máquina de Atwood permite estudiar el movimiento con aceleración reducida","La aceleración del sistema es a = g por (m1 - m2) / (m1 + m2)","La tensión de la cuerda es la misma para ambas masas al ser inextensible","Si las masas son casi iguales la aceleración es muy pequeña facilitando las mediciones"]'),
('fisica', 'bachillerato', '{1}', '["Un gas ideal cumple la ecuación de estado PV = nRT donde n son los moles","Al duplicar la temperatura absoluta manteniendo el volumen constante la presión se duplica","Al duplicar el volumen manteniendo la temperatura constante la presión se reduce a la mitad","La constante R tiene un valor de 8,314 julios por mol y kelvin","La ecuación de los gases ideales se cumple bien a presiones bajas y temperaturas altas"]'),
('fisica', 'bachillerato', '{1}', '["Un péndulo cónico describe un movimiento circular uniforme en el plano horizontal","La tensión de la cuerda se descompone en una componente vertical y otra horizontal","La componente vertical equilibra el peso del péndulo manteniéndolo a altura constante","La componente horizontal proporciona la fuerza centrípeta necesaria para el giro","El periodo del péndulo cónico depende de la longitud del hilo y el ángulo con la vertical"]'),
('fisica', 'bachillerato', '{1}', '["La transmisión de calor por conducción ocurre por contacto directo entre cuerpos a distinta temperatura","La ley de Fourier establece que el flujo de calor es proporcional al gradiente de temperatura","La conductividad térmica del material determina la eficacia de la conducción","Los metales son buenos conductores térmicos mientras que los plásticos y la madera son aislantes","En una pared compuesta el calor pasa sucesivamente por cada capa según su resistencia térmica"]'),
('fisica', 'bachillerato', '{1}', '["Se lanza un cuerpo verticalmente hacia arriba con una velocidad inicial conocida","Aplicamos la ecuación v = v0 - g por t para hallar el tiempo de subida cuando v es cero","La altura máxima se calcula con h = v0² / (2g) despejando de la ecuación de la energía","El cuerpo tarda el mismo tiempo en subir que en bajar por la simetría del movimiento","La velocidad al llegar al suelo tiene el mismo módulo que la velocidad inicial de lanzamiento"]'),
('fisica', 'bachillerato', '{1}', '["La ley de Coulomb describe la fuerza entre dos cargas eléctricas puntuales","La fuerza es proporcional al producto de las cargas e inversamente proporcional al cuadrado de la distancia","Cargas del mismo signo se repelen y cargas de signo contrario se atraen","La constante de Coulomb en el vacío vale aproximadamente 9 por 10 elevado a 9 N·m²/C²","La fuerza eléctrica es mucho más intensa que la gravitatoria para partículas subatómicas"]'),
('fisica', 'bachillerato', '{1}', '["Un resorte vertical sostiene un bloque que cuelga en equilibrio","En la posición de equilibrio el peso del bloque iguala la fuerza elástica del resorte","Si tiramos del bloque hacia abajo y lo soltamos oscila con movimiento armónico simple","El periodo de oscilación es T = 2π√(m/k) independientemente de la amplitud","La energía total del oscilador es constante e igual a la energía potencial elástica máxima"]'),
('fisica', 'bachillerato', '{1}', '["La fuerza de rozamiento estático impide que un cuerpo comience a moverse sobre una superficie","Su valor máximo es mu_e por N donde mu_e es el coeficiente de rozamiento estático","Cuando la fuerza aplicada supera el rozamiento estático máximo el cuerpo comienza a moverse","El rozamiento cinético actúa sobre cuerpos en movimiento y suele ser menor que el estático","El coeficiente de rozamiento depende de la naturaleza de las superficies en contacto"]'),
('fisica', 'bachillerato', '{1}', '["La transferencia de calor por radiación no necesita medio material y se propaga a la velocidad de la luz","Todos los cuerpos emiten radiación electromagnética según su temperatura","La ley de Stefan-Boltzmann establece que la potencia emitida es proporcional a T elevado a la cuarta","Un cuerpo negro es un emisor y absorbente perfecto de radiación","La ley de Wien relaciona la longitud de onda del máximo de emisión con la temperatura del cuerpo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('fisica', 'bachillerato', '{2}', '["Thomson descubrió el electrón proponiendo un modelo atómico de esfera positiva con electrones incrustados","Rutherford bombardeó una lámina de oro con partículas alfa descubriendo el núcleo atómico","Bohr postuló órbitas cuantizadas donde los electrones no emiten radiación","El modelo de Bohr explicó el espectro del hidrógeno pero falló con átomos multielectrónicos","La mecánica cuántica reemplazó las órbitas por orbitales describiendo la probabilidad de encontrar el electrón"]'),
('fisica', 'bachillerato', '{2}', '["Se coloca una carga puntual Q positiva en el origen de coordenadas","El campo eléctrico creado es radial dirigido hacia afuera y disminuye con r al cuadrado","El potencial eléctrico en un punto es V = kQ/r y decrece con la distancia","Una carga de prueba positiva q se mueve desde un punto A hasta otro B más cercano a Q","El trabajo del campo eléctrico sobre la carga es W = q por (VA - VB) que resulta negativo"]'),
('fisica', 'bachillerato', '{2}', '["Una espira conductora gira dentro de un campo magnético uniforme con velocidad angular constante","El flujo magnético a través de la espira varía sinusoidalmente con el tiempo","Según la ley de Faraday se induce una fuerza electromotriz proporcional a la variación del flujo","La fem inducida es máxima cuando el plano de la espira es paralelo al campo","Este es el principio de funcionamiento de un generador de corriente alterna"]'),
('fisica', 'bachillerato', '{2}', '["Una lente convergente recibe rayos de un objeto situado más allá del doble de la distancia focal","Los rayos paralelos al eje óptico refractan pasando por el foco imagen","El rayo que pasa por el centro óptico no se desvía al atravesar la lente","La imagen se forma real, invertida y de menor tamaño entre el foco y el doble de la focal","Aplicamos la ecuación de la lente delgada 1/f = 1/s prima menos 1/s para calcular la posición"]'),
('fisica', 'bachillerato', '{2}', '["Un núcleo de uranio 235 absorbe un neutrón térmico y se vuelve inestable","El núcleo se divide en dos fragmentos de masa intermedia más dos o tres neutrones","Los neutrones liberados pueden provocar nuevas fisiones en una reacción en cadena","La masa de los productos es menor que la de los reactivos liberando energía según E = mc²","En un reactor nuclear las barras de control absorben neutrones regulando la reacción"]'),
('fisica', 'bachillerato', '{2}', '["Una carga eléctrica se mueve en el interior de un campo magnético uniforme","La fuerza de Lorentz actúa perpendicularmente a la velocidad y al campo magnético","Como la fuerza es siempre perpendicular a la velocidad no realiza trabajo sobre la carga","La carga describe una trayectoria circular cuyo radio depende de su masa, velocidad y carga","El periodo del movimiento circular es independiente de la velocidad de la partícula"]'),
('fisica', 'bachillerato', '{2}', '["Se colocan dos placas paralelas conductoras cargadas con signo opuesto","Entre las placas se genera un campo eléctrico uniforme perpendicular a las superficies","La diferencia de potencial entre las placas es V = E por d donde d es la separación","Un electrón liberado cerca de la placa negativa acelera hacia la placa positiva","La energía cinética ganada por el electrón es igual a la carga por la diferencia de potencial"]'),
('fisica', 'bachillerato', '{2}', '["De Broglie postuló que toda partícula en movimiento tiene asociada una onda de longitud lambda","La longitud de onda de De Broglie es lambda = h/(m por v) donde h es la constante de Planck","Davisson y Germer confirmaron experimentalmente la difracción de electrones por un cristal de níquel","Para objetos macroscópicos la longitud de onda es despreciable y no se observan efectos cuánticos","La dualidad onda-corpúsculo es un principio fundamental de la mecánica cuántica"]'),
('fisica', 'bachillerato', '{2}', '["El principio de incertidumbre de Heisenberg limita la precisión simultánea de posición y momento","Cuanto más precisamente conocemos la posición de una partícula menos sabemos de su momento","La relación matemática establece que delta x por delta p es mayor o igual que h barra entre 2","Este principio no se debe a limitaciones experimentales sino a la naturaleza cuántica de la materia","La consecuencia es que no podemos hablar de trayectorias definidas para partículas subatómicas"]'),
('fisica', 'bachillerato', '{2}', '["Un rayo de luz pasa del aire al vidrio con un ángulo de incidencia mayor que cero grados","Parte de la luz se refleja con el mismo ángulo respecto a la normal de la superficie","La parte refractada se desvía hacia la normal porque el vidrio tiene mayor índice de refracción","La ley de Snell establece que n1 por seno de theta1 = n2 por seno de theta2","Si la luz pasa del vidrio al aire y supera el ángulo crítico se produce reflexión total interna"]'),
('fisica', 'bachillerato', '{2}', '["Un solenoide largo por el que circula corriente crea un campo magnético uniforme en su interior","El campo magnético interior es B = mu0 por n por I donde n es el número de espiras por metro","El campo fuera del solenoide es prácticamente nulo por la cancelación de las contribuciones","Si se varía la corriente en el solenoide se induce una fem en una bobina secundaria cercana","Este fenómeno de inducción mutua es el principio de funcionamiento del transformador eléctrico"]'),
('fisica', 'bachillerato', '{2}', '["La fusión nuclear une núcleos ligeros como el deuterio y el tritio formando helio","La masa de los productos es menor que la de los reactivos y la diferencia se libera como energía","La fusión requiere temperaturas de millones de grados para vencer la repulsión coulombiana","En las estrellas la fusión del hidrógeno en helio es la fuente principal de energía","Los reactores de fusión experimentales como el ITER buscan confinar el plasma con campos magnéticos"]'),
('fisica', 'bachillerato', '{2}', '["La desintegración radiactiva alfa emite un núcleo de helio-4 reduciendo Z en 2 y A en 4","La desintegración beta menos convierte un neutrón en protón emitiendo un electrón y un antineutrino","La desintegración gamma emite un fotón de alta energía sin cambiar Z ni A del núcleo","La vida media es el tiempo en que se desintegra la mitad de los átomos radiactivos","La actividad de una muestra decrece exponencialmente según N = N0 por e elevado a menos lambda t"]'),
('fisica', 'bachillerato', '{2}', '["Un condensador de placas paralelas se conecta a una batería y se carga completamente","La carga almacenada es Q = C por V donde C es la capacidad y V el voltaje de la batería","Se desconecta la batería y se introduce un dieléctrico entre las placas","La capacidad aumenta en un factor igual a la constante dieléctrica del material","El voltaje entre las placas disminuye pero la carga se mantiene constante"]'),
('fisica', 'bachillerato', '{2}', '["Una bobina toroidal de N espiras por la que circula una corriente I genera un campo magnético","Aplicamos la ley de Ampère a lo largo de una línea cerrada circular concéntrica con el toroide","La integral de B por dl es igual a mu0 por N por I para la línea dentro del toroide","El campo magnético dentro del toroide es B = mu0NI / (2 pi r) y varía con el radio","Fuera del toroide el campo magnético es nulo porque no encierra corriente neta"]'),
('fisica', 'bachillerato', '{2}', '["Un espejo cóncavo recibe rayos paralelos al eje principal procedentes de un objeto lejano","Los rayos se reflejan convergiendo en el foco del espejo situado a la mitad del radio de curvatura","Para un objeto entre el centro de curvatura y el infinito la imagen es real e invertida","Si el objeto está entre el foco y el espejo la imagen es virtual, derecha y aumentada","La ecuación del espejo 1/f = 1/s + 1/s prima permite calcular la posición de la imagen"]'),
('fisica', 'bachillerato', '{2}', '["Se conecta una bobina con autoinducción L a una fuente de corriente continua con un interruptor","Al cerrar el interruptor la corriente no alcanza instantáneamente su valor máximo","La bobina genera una fem autoinducida que se opone al cambio de corriente según la ley de Lenz","La corriente crece exponencialmente con constante de tiempo tau = L/R","Cuando la corriente se estabiliza la fem autoinducida se anula y la bobina actúa como un conductor"]'),
('fisica', 'bachillerato', '{2}', '["La energía de ligadura nuclear es la energía necesaria para separar todos los nucleones del núcleo","Se calcula como la diferencia de masa entre los nucleones libres y el núcleo multiplicada por c²","El defecto de masa explica que los núcleos tengan menos masa que la suma de sus componentes","Los núcleos con mayor energía de ligadura por nucleón son los más estables como el hierro-56","La curva de energía de ligadura por nucleón explica por qué la fisión y la fusión liberan energía"]'),
('fisica', 'bachillerato', '{2}', '["Un circuito LC ideal oscila con frecuencia propia f = 1/(2π√LC)","Inicialmente el condensador está cargado y toda la energía es eléctrica","La corriente comienza a fluir descargando el condensador y almacenando energía en la bobina","Cuando el condensador se descarga completamente toda la energía es magnética en la bobina","El proceso se invierte y la energía oscila entre el condensador y la bobina indefinidamente"]'),
('fisica', 'bachillerato', '{2}', '["Las leyes de Kepler describen el movimiento planetario en el sistema solar","La primera ley establece que las órbitas son elipses con el Sol en uno de los focos","La segunda ley dice que el radio vector barre áreas iguales en tiempos iguales","La tercera ley relaciona el cuadrado del periodo con el cubo del semieje mayor de la órbita","Newton demostró que las tres leyes de Kepler se deducen de la ley de gravitación universal"]'),
('fisica', 'bachillerato', '{2}', '["Un haz de luz blanca incide sobre una red de difracción con miles de rendijas por milímetro","Cada rendija actúa como una fuente secundaria de ondas según el principio de Huygens","Las ondas procedentes de rendijas consecutivas interfieren constructivamente para ángulos específicos","La condición de máximo es d por seno theta = m por lambda donde m es el orden del máximo","La red dispersa la luz blanca en sus colores componentes formando un espectro visible"]'),
('fisica', 'bachillerato', '{2}', '["La ley de Gauss establece que el flujo eléctrico a través de una superficie cerrada es Q/epsilon0","Para una esfera conductora cargada el campo exterior es idéntico al de una carga puntual","En el interior de un conductor en equilibrio el campo eléctrico es siempre nulo","Toda la carga neta se distribuye en la superficie exterior del conductor","Dentro de una cavidad conductora sin cargas el campo eléctrico también es cero efecto jaula de Faraday"]'),
('fisica', 'bachillerato', '{2}', '["La experiencia de Young hace pasar luz monocromática por dos rendijas paralelas muy próximas","Las ondas difractadas por ambas rendijas se superponen en una pantalla lejana","Se observa un patrón de franjas brillantes y oscuras alternadas en la pantalla","La separación entre franjas brillantes consecutivas depende de la longitud de onda y la distancia entre rendijas","Esta experiencia demostró la naturaleza ondulatoria de la luz en el siglo XIX"]'),
('fisica', 'bachillerato', '{2}', '["Los rayos X se producen cuando electrones acelerados impactan contra un blanco metálico","Los electrones frenan bruscamente emitiendo radiación de frenado o bremsstrahlung","Además se producen rayos X característicos cuando electrones internos son expulsados del átomo","Los electrones de capas superiores llenan la vacante emitiendo fotones de energía específica","El espectro de rayos X muestra un fondo continuo de frenado más las líneas características del material"]'),
('fisica', 'bachillerato', '{2}', '["El campo magnético terrestre se origina por corrientes de convección en el núcleo externo líquido","Las líneas de campo salen del polo norte magnético situado cerca del polo sur geográfico","La intensidad del campo terrestre es del orden de 50 microteslas en la superficie","El campo magnético terrestre desvía las partículas cargadas del viento solar protegiendo la vida","Las inversiones de polaridad magnética quedan registradas en las rocas del fondo oceánico"]'),
('fisica', 'bachillerato', '{2}', '["En el efecto Compton un fotón de rayos X choca con un electrón libre","El fotón sale dispersado con menor energía y por tanto mayor longitud de onda","El electrón sale despedido con energía cinética igual a la perdida por el fotón","La variación de longitud de onda depende del ángulo de dispersión según la fórmula de Compton","Este efecto confirmó que los fotones se comportan como partículas con momento lineal p = h/lambda"]'),
('fisica', 'bachillerato', '{2}', '["Un alambre recto infinito por el que circula corriente I genera un campo magnético circular","Las líneas de campo son circunferencias concéntricas al alambre en planos perpendiculares","La intensidad del campo es B = mu0 I / (2 pi r) y decrece con la distancia al hilo","La dirección del campo se determina con la regla de la mano derecha","Dos hilos paralelos con corrientes en el mismo sentido se atraen según la ley de Ampère"]'),
('fisica', 'bachillerato', '{2}', '["La radiación del cuerpo negro no podía explicarse con la física clásica originando la catástrofe ultravioleta","Planck postuló que la energía se emite y absorbe en cuantos discretos E = h por f","Esta hipótesis cuántica resolvió el problema prediciendo correctamente el espectro de emisión","Einstein extendió la idea de Planck para explicar el efecto fotoeléctrico con fotones","La cuantización de la energía fue el nacimiento de la mecánica cuántica a principios del siglo XX"]'),
('fisica', 'bachillerato', '{2}', '["Se aplica una diferencia de potencial entre los electrodos de un tubo de vacío con gas residual","Los electrones acelerados ionizan los átomos del gas produciendo más electrones e iones","Los iones positivos golpean el cátodo arrancando más electrones secundarios","Se establece una descarga eléctrica que produce luz característica del gas ionizado","Thomson utilizó tubos de descarga para medir la relación carga-masa del electrón"]'),
('fisica', 'bachillerato', '{2}', '["Un protón y un electrón se atraen eléctricamente formando el átomo de hidrógeno","En el modelo de Bohr el electrón solo puede ocupar órbitas con momento angular cuantizado","Al absorber un fotón con energía exacta el electrón salta a un nivel superior","Al caer a un nivel inferior emite un fotón cuya energía es la diferencia entre niveles","Las series espectrales de Lyman, Balmer y Paschen corresponden a transiciones hacia distintos niveles"]'),
('fisica', 'bachillerato', '{2}', '["Un campo eléctrico variable en el tiempo genera un campo magnético según la ley de Ampère-Maxwell","A su vez un campo magnético variable genera un campo eléctrico según la ley de Faraday","Esta retroalimentación permite la propagación de ondas electromagnéticas sin necesidad de medio material","Maxwell predijo que las ondas electromagnéticas viajan a la velocidad de la luz","Hertz confirmó experimentalmente la existencia de las ondas electromagnéticas en 1887"]'),
('fisica', 'bachillerato', '{2}', '["La energía de un fotón es E = h por f donde h es la constante de Planck y f la frecuencia","Los fotones de luz ultravioleta tienen más energía que los de luz visible","Los fotones de rayos gamma tienen la mayor energía del espectro electromagnético","La longitud de onda del fotón es inversamente proporcional a su energía según lambda = hc/E","La energía del fotón determina si puede ionizar átomos o provocar reacciones nucleares"]'),
('fisica', 'bachillerato', '{2}', '["La velocidad de la luz en el vacío es la misma para todos los observadores según la relatividad especial","La dilatación temporal hace que un reloj en movimiento mida tiempos más largos para un observador en reposo","La contracción de la longitud reduce las dimensiones de un objeto en la dirección de su movimiento","La masa relativista aumenta con la velocidad acercándose a infinito cuando v tiende a c","La equivalencia masa-energía E = mc² establece que masa y energía son manifestaciones del mismo fenómeno"]'),
('fisica', 'bachillerato', '{2}', '["La datación radiactiva utiliza la vida media de isótopos para calcular la edad de muestras","El carbono-14 tiene una vida media de 5730 años y se usa para datar restos orgánicos","Se mide la proporción de C-14 respecto al C-12 en la muestra y se compara con la atmosférica","Aplicando la ley de desintegración exponencial se calcula el tiempo transcurrido desde la muerte del organismo","Para rocas más antiguas se utilizan isótopos de mayor vida media como el potasio-40 o el uranio-238"]'),
('fisica', 'bachillerato', '{2}', '["Una onda electromagnética plana tiene campos eléctrico y magnético perpendiculares entre sí","Ambos campos oscilan en fase y son perpendiculares a la dirección de propagación","La relación entre los módulos de los campos es E = c por B en todo instante","La intensidad de la onda es proporcional al cuadrado de la amplitud del campo eléctrico","Las ondas electromagnéticas transportan energía y momento lineal a la velocidad de la luz"]'),
('fisica', 'bachillerato', '{2}', '["La ley de Biot-Savart permite calcular el campo magnético creado por un elemento de corriente","El campo creado por un elemento dl es perpendicular al plano formado por dl y el vector posición","Su módulo es proporcional a la corriente y al seno del ángulo entre dl y r","Para un hilo circular de radio R la integración da B = mu0 I / (2R) en el centro","La ley de Biot-Savart se aplica a cualquier geometría de conductor recorrido por corriente"]'),
('fisica', 'bachillerato', '{2}', '["Un interferómetro de Michelson divide un haz de luz en dos caminos perpendiculares","Cada haz se refleja en un espejo y vuelve para recombinarse en el divisor de haz","Si los caminos ópticos son iguales se produce interferencia constructiva en el centro","Al desplazar un espejo una distancia d el patrón de interferencia cambia por la diferencia de camino","Michelson y Morley usaron este interferómetro para demostrar la inexistencia del éter luminífero"]'),
('fisica', 'bachillerato', '{2}', '["Un fotón de alta energía cerca de un núcleo puede crear un par electrón-positrón","La energía mínima del fotón debe ser al menos 2 por m_e por c² que es 1,022 MeV","El exceso de energía se reparte como energía cinética entre el electrón y el positrón","El núcleo cercano absorbe el retroceso conservando el momento lineal del sistema","El proceso inverso, la aniquilación, ocurre cuando electrón y positrón se encuentran emitiendo dos fotones gamma"]'),
('fisica', 'bachillerato', '{2}', '["El efecto Hall se produce cuando una corriente eléctrica circula en presencia de un campo magnético transversal","La fuerza de Lorentz desvía los portadores de carga hacia un lado del conductor","Se acumula carga en un lado creando un campo eléctrico transversal llamado voltaje de Hall","El equilibrio se alcanza cuando la fuerza eléctrica iguala a la fuerza magnética sobre los portadores","Midiendo el voltaje de Hall se puede determinar el signo y la densidad de los portadores de carga"]'),
('fisica', 'bachillerato', '{2}', '["La superconductividad aparece cuando ciertos materiales se enfrían por debajo de su temperatura crítica","La resistencia eléctrica del material cae bruscamente a cero permitiendo corrientes perpetuas","El efecto Meissner expulsa completamente el campo magnético del interior del superconductor","Los pares de Cooper son electrones apareados que se mueven sin dispersión en la red cristalina","Los superconductores se utilizan en electroimanes de resonancia magnética y aceleradores de partículas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('matematicas', 'bachillerato', '{1}', '["Para resolver un sistema 3x3 por Gauss escribimos la matriz ampliada del sistema","Mediante operaciones elementales de fila transformamos la matriz en forma escalonada","La última ecuación tiene una sola incógnita que se resuelve directamente","Sustituimos hacia arriba para ir obteniendo las demás incógnitas una a una","Comprobamos la solución sustituyendo los valores en las ecuaciones originales"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular un límite con indeterminación 0/0 intentamos factorizar numerador y denominador","Buscamos la raíz común que produce la anulación simultánea de ambos polinomios","Factorizamos y simplificamos el factor común que causa la indeterminación","Evaluamos el límite de la expresión simplificada sustituyendo directamente el valor de x","Si no se puede factorizar podemos aplicar la regla de L Hôpital derivando numerador y denominador"]'),
('matematicas', 'bachillerato', '{1}', '["Para derivar un producto de funciones aplicamos la regla del producto de Leibniz","La derivada de f por g es f prima por g más f por g prima","Calculamos por separado la derivada de cada factor","Sustituimos en la fórmula y simplificamos la expresión resultante","Verificamos el resultado evaluando en un punto y comparando con la pendiente numérica"]'),
('matematicas', 'bachillerato', '{1}', '["Para derivar una función compuesta aplicamos la regla de la cadena","Identificamos la función exterior y la función interior de la composición","La derivada es la derivada de la exterior evaluada en la interior multiplicada por la derivada de la interior","Calculamos cada derivada parcial paso a paso siguiendo el orden de composición","Simplificamos el resultado final agrupando términos comunes si es posible"]'),
('matematicas', 'bachillerato', '{1}', '["Para hallar la ecuación de la recta tangente a una curva en un punto calculamos la derivada","Evaluamos la derivada en el punto de tangencia para obtener la pendiente m","Usamos la ecuación punto-pendiente: y - y0 = m por (x - x0)","Desarrollamos la ecuación y la escribimos en forma explícita y = mx + n","La recta normal en el mismo punto tiene pendiente -1/m perpendicular a la tangente"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular el determinante de una matriz 3x3 desarrollamos por la primera fila","Cada cofactor es el menor complementario multiplicado por el signo correspondiente","Los menores complementarios son determinantes 2x2 que se calculan como ad - bc","Sumamos los tres productos de elemento por cofactor para obtener el determinante","Si el determinante es cero la matriz no es invertible y el sistema asociado puede ser incompatible"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver una inecuación de segundo grado igualamos primero a cero y hallamos las raíces","Las raíces dividen la recta real en intervalos donde el polinomio mantiene signo constante","Evaluamos el signo del polinomio en un punto de cada intervalo para determinar el signo","Seleccionamos los intervalos que cumplen la desigualdad pedida","Escribimos la solución en forma de intervalo comprobando si los extremos se incluyen o no"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular la inversa de una matriz 2x2 primero verificamos que el determinante sea distinto de cero","La inversa es 1/det multiplicado por la matriz adjunta","En la adjunta intercambiamos los elementos de la diagonal principal y cambiamos el signo de los otros","Multiplicamos la matriz adjunta por 1/det para obtener la inversa","Comprobamos que A por A inversa da la matriz identidad"]'),
('matematicas', 'bachillerato', '{1}', '["Queremos estudiar la continuidad de una función a trozos en el punto de cambio de definición","Calculamos el límite por la izquierda sustituyendo en la expresión del primer trozo","Calculamos el límite por la derecha sustituyendo en la expresión del segundo trozo","Evaluamos la función en el punto para comprobar si está definida allí","Si los tres valores coinciden la función es continua en ese punto"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver un sistema de ecuaciones no lineales expresamos una variable en función de la otra","Sustituimos la expresión obtenida en la segunda ecuación del sistema","Resolvemos la ecuación resultante de una sola incógnita factorizando o usando la fórmula general","Cada solución de esta incógnita se sustituye en la primera expresión para hallar la otra variable","Obtenemos los pares de soluciones y los verificamos en ambas ecuaciones originales"]'),
('matematicas', 'bachillerato', '{1}', '["Para estudiar el crecimiento de una función calculamos su derivada primera","Igualamos la derivada a cero para encontrar los puntos críticos candidatos a extremos","Estudiamos el signo de la derivada a la izquierda y derecha de cada punto crítico","Si la derivada pasa de positiva a negativa hay un máximo relativo en ese punto","Si pasa de negativa a positiva hay un mínimo relativo en ese punto"]'),
('matematicas', 'bachillerato', '{1}', '["Para estudiar la curvatura de una función calculamos la derivada segunda","Los puntos de inflexión son aquellos donde la derivada segunda se anula y cambia de signo","Si la segunda derivada es positiva la función es cóncava hacia arriba en ese intervalo","Si la segunda derivada es negativa la función es cóncava hacia abajo","Los puntos de inflexión separan intervalos de distinta concavidad"]'),
('matematicas', 'bachillerato', '{1}', '["Para representar gráficamente una función racional primero hallamos su dominio excluyendo los ceros del denominador","Calculamos las asíntotas verticales en los valores donde el denominador se anula","La asíntota horizontal se determina estudiando el límite cuando x tiende a más y menos infinito","Hallamos los puntos de corte con los ejes igualando la función a cero y evaluando en x = 0","Unimos toda la información con la monotonía y curvatura para dibujar la gráfica completa"]'),
('matematicas', 'bachillerato', '{1}', '["Para hallar la matriz de un sistema de ecuaciones lineales extraemos los coeficientes de las incógnitas","Formamos la matriz de coeficientes A y el vector de términos independientes b","Calculamos el rango de A y el de la matriz ampliada para clasificar el sistema por Rouché-Frobenius","Si rango A = rango A* = n el sistema es compatible determinado con solución única","Si rango A = rango A* menor que n el sistema es compatible indeterminado con infinitas soluciones"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular un límite con indeterminación infinito menos infinito racionalizamos o operamos algebraicamente","Si hay raíces cuadradas multiplicamos y dividimos por el conjugado para eliminar la indeterminación","Simplificamos la expresión obtenida hasta poder evaluar el límite directamente","Si el resultado es un número finito ese es el valor del límite","Si el resultado tiende a infinito concluimos que el límite no existe como número real"]'),
('matematicas', 'bachillerato', '{1}', '["Las combinaciones cuentan subconjuntos de k elementos elegidos de un conjunto de n sin importar el orden","Se calculan con la fórmula C(n,k) = n! / (k! por (n-k)!)","Las variaciones sin repetición son V(n,k) = n! / (n-k)! y sí importa el orden","Las permutaciones de n elementos son P(n) = n! que cuentan los reordenamientos totales","Para saber qué fórmula usar debemos preguntarnos si importa el orden y si hay repetición"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver una ecuación exponencial tomamos logaritmos en ambos miembros","Aplicamos la propiedad del logaritmo de una potencia para bajar el exponente","El exponente pasa a multiplicar al logaritmo de la base","Despejamos la incógnita realizando las operaciones algebraicas necesarias","Comprobamos la solución sustituyendo en la ecuación exponencial original"]'),
('matematicas', 'bachillerato', '{1}', '["Dado un vector u = (3,4) calculamos su módulo como raíz cuadrada de 3² + 4² = 5","El vector unitario en la dirección de u se obtiene dividiendo cada componente entre el módulo","Para calcular el producto escalar de u = (3,4) y v = (1,2) sumamos 3·1 + 4·2 = 11","El ángulo entre u y v se obtiene con cos(alfa) = u·v / (|u|·|v|)","Si el producto escalar es cero los vectores son perpendiculares entre sí"]'),
('matematicas', 'bachillerato', '{1}', '["Para derivar un cociente de funciones aplicamos la regla del cociente","La derivada de f/g es (f prima por g menos f por g prima) todo dividido entre g al cuadrado","Calculamos las derivadas del numerador y del denominador por separado","Sustituimos en la fórmula y desarrollamos el numerador del resultado","Simplificamos la fracción resultante si es posible factorizando términos comunes"]'),
('matematicas', 'bachillerato', '{1}', '["La distribución binomial modela el número de éxitos en n ensayos independientes de Bernoulli","La probabilidad de cada ensayo es constante e igual a p con q = 1 - p","La probabilidad de obtener exactamente k éxitos es C(n,k) por p^k por q^(n-k)","La media de la distribución binomial es mu = n por p","La desviación típica es sigma = raíz de n por p por q"]'),
('matematicas', 'bachillerato', '{1}', '["Para demostrar una propiedad por inducción verificamos primero el caso base para n = 1","Suponemos que la propiedad se cumple para un valor genérico n = k como hipótesis de inducción","Demostramos que bajo esa hipótesis la propiedad también se cumple para n = k + 1","Esta prueba garantiza que si se cumple para 1 también para 2, para 3 y así sucesivamente","Concluimos que la propiedad es cierta para todo número natural n"]'),
('matematicas', 'bachillerato', '{1}', '["Para hallar la ecuación de una circunferencia a partir de tres puntos sustituimos cada punto en la ecuación general","La ecuación general es x² + y² + Dx + Ey + F = 0 con tres incógnitas D, E y F","Cada punto genera una ecuación lineal en D, E y F formando un sistema 3x3","Resolvemos el sistema por cualquier método y obtenemos los valores de D, E y F","El centro de la circunferencia es (-D/2, -E/2) y el radio es raíz de (D²/4 + E²/4 - F)"]'),
('matematicas', 'bachillerato', '{1}', '["La probabilidad condicionada P(A|B) mide la probabilidad de A sabiendo que ha ocurrido B","Se calcula como P(A intersección B) dividido entre P(B)","Si A y B son independientes entonces P(A|B) = P(A) y la ocurrencia de B no afecta a A","El teorema de la probabilidad total permite calcular P(A) sumando las contribuciones de cada partición","El teorema de Bayes permite actualizar probabilidades a la luz de nueva información"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular el límite de (1 + 1/n)^n cuando n tiende a infinito reconocemos la indeterminación 1^infinito","Aplicamos la fórmula general: L = e elevado al límite de (f(x) - 1) por g(x)","El exponente tiende a 1/n por n = 1 que es finito y no nulo","Evaluamos la exponencial y obtenemos que el límite es el número e","Este resultado define el número e = 2,71828... base del logaritmo neperiano"]'),
('matematicas', 'bachillerato', '{1}', '["Para sumar dos matrices A y B ambas deben tener las mismas dimensiones","Cada elemento de la matriz suma es la suma de los elementos correspondientes de A y B","El producto por un escalar multiplica cada elemento de la matriz por ese número","La suma de matrices es conmutativa y asociativa al igual que la suma de números","La matriz nula actúa como elemento neutro de la suma de matrices"]'),
('matematicas', 'bachillerato', '{1}', '["Queremos hallar la distancia de un punto P a una recta r dada por ax + by + c = 0","Aplicamos la fórmula d = |ax0 + by0 + c| / raíz(a² + b²) con P = (x0, y0)","Sustituimos las coordenadas del punto en la ecuación de la recta","Calculamos el valor absoluto del numerador y la raíz del denominador","El cociente nos da la distancia perpendicular del punto a la recta"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular la derivada de la función f(x) = ln(x) partimos de la definición de derivada","El incremento del logaritmo es ln(x + h) - ln(x) = ln((x+h)/x) = ln(1 + h/x)","Dividimos entre h y tomamos el límite cuando h tiende a cero","Reescribimos como (1/h)·ln(1 + h/x) y reconocemos que tiende a 1/x","Concluimos que la derivada del logaritmo neperiano es f prima(x) = 1/x"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver una ecuación trigonométrica como 2·sen(x) - 1 = 0 aislamos la función trigonométrica","Obtenemos sen(x) = 1/2 y buscamos los ángulos cuyo seno vale 1/2","La solución principal es x = 30 grados o pi/6 radianes en el primer cuadrante","Por la simetría del seno hay otra solución en el segundo cuadrante: x = 150 grados o 5pi/6","La solución general añade múltiplos de 2pi: x = pi/6 + 2k·pi y x = 5pi/6 + 2k·pi"]'),
('matematicas', 'bachillerato', '{1}', '["El binomio de Newton desarrolla (a + b)^n como suma de n+1 términos","El término general es C(n,k) por a^(n-k) por b^k para k desde 0 hasta n","Los coeficientes binomiales C(n,k) se pueden leer en el triángulo de Pascal","Para hallar un término específico solo necesitamos calcular el coeficiente y las potencias correspondientes","El desarrollo tiene n+1 términos y la suma de los exponentes en cada término siempre es n"]'),
('matematicas', 'bachillerato', '{1}', '["Para hallar la ecuación de la elipse identificamos sus semiejes a y b y el centro","La ecuación canónica es x²/a² + y²/b² = 1 con el centro en el origen","Los focos se sitúan a distancia c del centro donde c² = a² - b² siendo a el semieje mayor","La excentricidad e = c/a mide cuánto se aleja la elipse de una circunferencia","Los vértices están en los extremos de los semiejes sobre los ejes de simetría"]'),
('matematicas', 'bachillerato', '{1}', '["Para derivar implícitamente la ecuación x² + y² = 25 derivamos ambos miembros respecto a x","La derivada de x² es 2x y la de y² es 2y·y prima aplicando la regla de la cadena","Obtenemos 2x + 2y·y prima = 0 y despejamos y prima = -x/y","La pendiente de la tangente a la circunferencia en un punto (x0, y0) es -x0/y0","Verificamos que la tangente es perpendicular al radio en el punto de tangencia"]'),
('matematicas', 'bachillerato', '{1}', '["Una sucesión aritmética tiene diferencia constante d entre términos consecutivos","El término general es an = a1 + (n-1)·d donde a1 es el primer término","La suma de los n primeros términos es Sn = n·(a1 + an)/2","Una sucesión geométrica tiene razón constante r entre términos consecutivos","La suma de los n primeros términos de una geométrica es Sn = a1·(r^n - 1)/(r - 1)"]'),
('matematicas', 'bachillerato', '{1}', '["Para hallar los autovalores de una matriz A resolvemos det(A - lambda·I) = 0","La ecuación resultante es el polinomio característico de grado igual al tamaño de la matriz","Las raíces del polinomio característico son los autovalores de la matriz","Para cada autovalor resolvemos el sistema (A - lambda·I)·v = 0 para hallar los autovectores","Los autovectores asociados a autovalores distintos son linealmente independientes"]'),
('matematicas', 'bachillerato', '{1}', '["Para optimizar una función en un intervalo cerrado primero hallamos los puntos críticos en el interior","Calculamos la derivada e igualamos a cero para encontrar candidatos a extremos","Evaluamos la función en cada punto crítico y en los extremos del intervalo","El mayor valor corresponde al máximo absoluto y el menor al mínimo absoluto","El teorema de Weierstrass garantiza la existencia de máximo y mínimo en intervalos cerrados y acotados"]'),
('matematicas', 'bachillerato', '{1}', '["Los logaritmos convierten productos en sumas y cocientes en restas","El logaritmo de una potencia baja el exponente multiplicándolo: log(a^n) = n·log(a)","Para cambiar de base usamos log_b(x) = log_a(x) / log_a(b)","El logaritmo neperiano usa base e y el logaritmo decimal usa base 10","Estas propiedades permiten simplificar ecuaciones exponenciales y resolver problemas de crecimiento"]'),
('matematicas', 'bachillerato', '{1}', '["Las funciones trigonométricas seno y coseno son periódicas con periodo 2·pi","La función tangente tiene periodo pi y presenta asíntotas verticales donde el coseno se anula","La identidad fundamental es sen²(x) + cos²(x) = 1 para todo x real","Las fórmulas del ángulo doble expresan sen(2x) = 2·sen(x)·cos(x)","Las fórmulas del ángulo mitad permiten resolver integrales y ecuaciones trigonométricas complejas"]'),
('matematicas', 'bachillerato', '{1}', '["Para aplicar el teorema de Bolzano comprobamos que la función es continua en el intervalo cerrado","Evaluamos la función en los extremos del intervalo y verificamos que tiene signos opuestos","Si f(a) y f(b) tienen signos distintos existe al menos un c en el intervalo donde f(c) = 0","Este teorema garantiza la existencia de raíz pero no indica cómo encontrarla exactamente","Para aproximar la raíz podemos usar bisección dividiendo el intervalo sucesivamente"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver un sistema por la regla de Cramer calculamos el determinante de la matriz de coeficientes","Si el determinante es distinto de cero el sistema tiene solución única","Cada incógnita se calcula sustituyendo su columna de coeficientes por la de términos independientes","El valor de la incógnita es el cociente del determinante modificado entre el determinante original","Comprobamos los resultados sustituyendo las soluciones en las ecuaciones del sistema"]'),
('matematicas', 'bachillerato', '{1}', '["Para estudiar la derivabilidad de una función a trozos en el punto de unión necesitamos que sea continua","Calculamos la derivada por la izquierda usando la expresión del primer trozo","Calculamos la derivada por la derecha usando la expresión del segundo trozo","Si ambas derivadas laterales coinciden la función es derivable en ese punto","Si no coinciden la función tiene un punto anguloso y no es derivable allí"]'),
('matematicas', 'bachillerato', '{1}', '["Para calcular la tasa de variación media de una función en un intervalo usamos (f(b)-f(a))/(b-a)","Esta expresión coincide con la pendiente de la recta secante que une los puntos (a,f(a)) y (b,f(b))","La tasa de variación instantánea es el límite de la tasa media cuando el intervalo tiende a cero","Este límite es precisamente la derivada de la función en el punto a","La derivada mide la rapidez con que varía la función en cada instante"]'),
('matematicas', 'bachillerato', '{1}', '["Para resolver un problema de programación lineal identificamos las restricciones como inecuaciones lineales","Representamos gráficamente cada restricción como una recta y sombreamos el lado que cumple la desigualdad","La intersección de todas las regiones sombreadas forma el conjunto factible o polígono convexo","La función objetivo alcanza su máximo o mínimo en uno de los vértices del polígono factible","Evaluamos la función objetivo en cada vértice y seleccionamos el que optimiza el resultado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('matematicas', 'bachillerato', '{2}', '["Para integrar por sustitución identificamos una función interior g(x) y hacemos el cambio t = g(x)","Calculamos dt = g prima(x) dx y expresamos todo el integrando en función de t","Integramos la función resultante en la variable t aplicando las reglas habituales","Deshacemos el cambio sustituyendo t por g(x) en el resultado","Añadimos la constante de integración y comprobamos derivando que obtenemos el integrando original"]'),
('matematicas', 'bachillerato', '{2}', '["Para resolver un problema de optimización con restricciones primero identificamos la función objetivo","Expresamos la función objetivo en una sola variable usando la restricción dada","Calculamos la derivada e igualamos a cero para encontrar los puntos críticos","Verificamos que el punto crítico es un máximo o mínimo usando la segunda derivada","Calculamos el valor óptimo y respondemos en el contexto del problema original"]'),
('matematicas', 'bachillerato', '{2}', '["Para tipificar una variable X con distribución N(mu, sigma) usamos Z = (X - mu) / sigma","La variable Z resultante sigue una distribución normal estándar N(0, 1)","Buscamos la probabilidad correspondiente en la tabla de la normal estándar","Si el valor buscado es negativo usamos la simetría: P(Z < -a) = 1 - P(Z < a)","Interpretamos el resultado como la probabilidad de que la variable original tome valores en el rango pedido"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la ecuación de un plano que pasa por tres puntos no alineados formamos dos vectores directores","Los vectores se obtienen restando las coordenadas del primer punto a los otros dos","Calculamos el vector normal al plano como el producto vectorial de los dos vectores directores","La ecuación del plano es n1(x-x0) + n2(y-y0) + n3(z-z0) = 0 usando el punto y la normal","Simplificamos para obtener la forma general Ax + By + Cz + D = 0"]'),
('matematicas', 'bachillerato', '{2}', '["Para integrar una función racional descomponemos la fracción en fracciones simples","Si el grado del numerador es mayor o igual que el del denominador primero dividimos","Factorizamos el denominador en factores lineales y cuadráticos irreducibles","Cada factor lineal aporta una fracción A/(x-a) y cada cuadrático aporta (Bx+C)/(x²+bx+c)","Integramos cada fracción simple por separado usando logaritmos y arcotangentes"]'),
('matematicas', 'bachillerato', '{2}', '["Para calcular el volumen de un cuerpo de revolución usamos el método de discos","Giramos la curva y = f(x) alrededor del eje X generando un sólido de revolución","El volumen de cada disco infinitesimal es pi por f(x)² por dx","Integramos pi por f(x)² desde x = a hasta x = b para obtener el volumen total","Si la rotación es alrededor del eje Y usamos el método de capas cilíndricas o el cambio de variable"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la posición relativa de dos rectas en el espacio calculamos sus vectores directores","Si los vectores son proporcionales las rectas son paralelas o coincidentes","Si no son proporcionales formamos el determinante con los vectores directores y el vector de unión","Si el determinante es cero las rectas se cortan en un punto que hallamos resolviendo el sistema","Si el determinante es distinto de cero las rectas se cruzan sin cortarse"]'),
('matematicas', 'bachillerato', '{2}', '["Para calcular un intervalo de confianza para la media con varianza conocida fijamos el nivel de confianza","El valor z_alfa/2 se obtiene de la tabla de la normal estándar para el nivel elegido","El error máximo admisible es E = z_alfa/2 por sigma / raíz(n)","El intervalo de confianza es (x barra - E, x barra + E) centrado en la media muestral","Para reducir la amplitud del intervalo debemos aumentar el tamaño de la muestra n"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la distancia de un punto a un plano usamos la fórmula con la ecuación del plano","Si el plano es Ax + By + Cz + D = 0 y el punto es P(x0, y0, z0)","La distancia es d = |Ax0 + By0 + Cz0 + D| / raíz(A² + B² + C²)","Sustituimos las coordenadas del punto y los coeficientes del plano en la fórmula","El resultado es siempre positivo e indica la distancia perpendicular mínima"]'),
('matematicas', 'bachillerato', '{2}', '["Para diagonalizar una matriz A calculamos primero sus autovalores resolviendo det(A - λI) = 0","Para cada autovalor hallamos los autovectores resolviendo el sistema (A - λI)v = 0","Formamos la matriz P con los autovectores como columnas","La matriz diagonal D tiene los autovalores en la diagonal principal","Se cumple la relación A = P·D·P⁻¹ que permite calcular potencias de A fácilmente"]'),
('matematicas', 'bachillerato', '{2}', '["Para integrar por partes repetidamente una integral como x²·e^x elegimos u = x² y dv = e^x dx","Aplicamos la fórmula obteniendo x²·e^x - integral de 2x·e^x dx","La nueva integral requiere otra integración por partes con u = 2x y dv = e^x dx","Obtenemos x²·e^x - 2x·e^x + integral de 2·e^x dx","Resolvemos la última integral directamente y sumamos la constante de integración"]'),
('matematicas', 'bachillerato', '{2}', '["El teorema fundamental del cálculo establece que la integral definida es F(b) - F(a)","Donde F es cualquier primitiva de la función f que estamos integrando","Para aplicar Barrow primero calculamos una primitiva F de f","Evaluamos F en el extremo superior b y restamos F evaluada en el extremo inferior a","El resultado es el valor numérico del área con signo bajo la curva en ese intervalo"]'),
('matematicas', 'bachillerato', '{2}', '["Para determinar el tamaño muestral mínimo fijamos el nivel de confianza y el error máximo E","De la fórmula E = z_alfa/2 por sigma / raíz(n) despejamos n","Obtenemos n = (z_alfa/2 por sigma / E) al cuadrado","Si sigma es desconocido usamos una estimación previa o la desviación de una muestra piloto","Siempre redondeamos n al entero superior para garantizar el nivel de confianza deseado"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la ecuación de una recta en el espacio necesitamos un punto y un vector director","La ecuación paramétrica es (x, y, z) = (x0, y0, z0) + t·(a, b, c) con t parámetro real","Las ecuaciones continuas se obtienen despejando t: (x-x0)/a = (y-y0)/b = (z-z0)/c","La recta también se puede expresar como intersección de dos planos","Cada par de ecuaciones continuas define uno de esos planos que contienen a la recta"]'),
('matematicas', 'bachillerato', '{2}', '["Para resolver una integral trigonométrica como integral de sen³(x)·cos²(x) dx separamos un factor sen(x)","Escribimos sen²(x) = 1 - cos²(x) para expresar todo en función de cos(x)","Hacemos el cambio t = cos(x) con dt = -sen(x) dx","La integral se transforma en -(1 - t²)·t² dt que es un polinomio en t","Integramos el polinomio, deshacemos el cambio y añadimos la constante de integración"]'),
('matematicas', 'bachillerato', '{2}', '["Para un contraste de hipótesis unilateral establecemos H0 y H1 sobre el parámetro poblacional","Calculamos el estadístico de contraste z = (x barra - mu0) / (sigma / raíz(n))","Fijamos el nivel de significación alfa y determinamos la región crítica con la tabla de la normal","Si el estadístico cae en la región crítica rechazamos la hipótesis nula H0","Si no cae en la región crítica no tenemos evidencia suficiente para rechazar H0"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar el plano que contiene a una recta y pasa por un punto externo formamos tres vectores","Usamos el vector director de la recta y el vector que une un punto de la recta con el punto externo","El vector normal al plano es el producto vectorial de esos dos vectores","Escribimos la ecuación del plano usando el punto externo y la normal obtenida","Verificamos que todos los puntos de la recta satisfacen la ecuación del plano"]'),
('matematicas', 'bachillerato', '{2}', '["Para calcular el área de un triángulo en el espacio con vértices A, B y C formamos los vectores AB y AC","El producto vectorial AB × AC da un vector perpendicular al plano del triángulo","El módulo del producto vectorial es igual al área del paralelogramo formado por AB y AC","El área del triángulo es la mitad del módulo del producto vectorial","Esta fórmula se aplica en cualquier dimensión y es más directa que la fórmula de Herón"]'),
('matematicas', 'bachillerato', '{2}', '["Para optimizar el volumen de una caja sin tapa recortando cuadrados de lado x de cada esquina de una lámina","Las dimensiones de la base son (a - 2x) por (b - 2x) y la altura es x","El volumen es V(x) = x·(a - 2x)·(b - 2x) que expandimos para derivar más fácilmente","Derivamos e igualamos a cero para encontrar el valor de x que maximiza el volumen","Comprobamos con la segunda derivada que el punto crítico es un máximo en el dominio 0 < x < menor/2"]'),
('matematicas', 'bachillerato', '{2}', '["Para integrar una integral impropia de primera especie sustituimos el infinito por un parámetro M","Calculamos la integral definida desde a hasta M con las técnicas habituales","Evaluamos el límite del resultado cuando M tiende a infinito","Si el límite existe y es finito la integral impropia converge y ese límite es su valor","Si el límite es infinito o no existe la integral impropia diverge"]'),
('matematicas', 'bachillerato', '{2}', '["El teorema del valor medio de Lagrange garantiza que existe un c en (a,b) donde f prima(c) = (f(b)-f(a))/(b-a)","La función debe ser continua en el cerrado [a,b] y derivable en el abierto (a,b)","Geométricamente significa que hay un punto donde la tangente es paralela a la secante","Para hallar c derivamos f, igualamos a la pendiente de la secante y resolvemos la ecuación","Comprobamos que el valor de c obtenido pertenece al intervalo abierto (a,b)"]'),
('matematicas', 'bachillerato', '{2}', '["Para aplicar la regla de L Hôpital debemos tener una indeterminación del tipo 0/0 o infinito/infinito","Derivamos numerador y denominador por separado manteniendo la fracción","Si la nueva fracción vuelve a ser indeterminada podemos aplicar L Hôpital otra vez","Cuando la fracción ya no sea indeterminada evaluamos el límite directamente","El resultado coincide con el del límite original si se cumplen las condiciones del teorema"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar el simétrico de un punto P respecto a un plano primero calculamos la recta perpendicular al plano por P","La recta tiene como vector director el vector normal del plano y pasa por P","Hallamos el punto de intersección M de la recta con el plano resolviendo el sistema","El punto simétrico P prima es tal que M es el punto medio entre P y P prima","Calculamos P prima = 2M - P componente a componente"]'),
('matematicas', 'bachillerato', '{2}', '["Un problema pide maximizar el área de un rectángulo inscrito en una semicircunferencia de radio R","El rectángulo tiene base 2x y altura y con la restricción x² + y² = R²","Expresamos el área A = 2x·y en una sola variable usando y = raíz(R² - x²)","Derivamos A respecto a x e igualamos a cero para hallar el valor óptimo","El rectángulo de área máxima tiene x = R/raíz(2) y y = R/raíz(2) con área R²"]'),
('matematicas', 'bachillerato', '{2}', '["Para resolver un sistema por el método de Gauss-Jordan partimos de la matriz ampliada del sistema","Realizamos operaciones elementales de fila para llevar la parte izquierda a la forma identidad","Cada operación se aplica a toda la fila incluyendo la columna de términos independientes","Cuando la parte izquierda es la identidad la columna derecha contiene directamente la solución","Si aparece una fila de ceros a la izquierda con término independiente no nulo el sistema es incompatible"]'),
('matematicas', 'bachillerato', '{2}', '["Para discutir un sistema con parámetro calculamos el determinante en función del parámetro","Los valores del parámetro que anulan el determinante son los que cambian el tipo de sistema","Para esos valores estudiamos los rangos de la matriz de coeficientes y de la ampliada","Si los rangos coinciden e igualan al número de incógnitas el sistema es compatible determinado","Si difieren entre sí el sistema es incompatible para esos valores del parámetro"]'),
('matematicas', 'bachillerato', '{2}', '["Para calcular la probabilidad en una distribución normal no estándar primero tipificamos la variable","Si X sigue N(50, 4) y queremos P(X < 58) calculamos Z = (58 - 50)/4 = 2","Buscamos P(Z < 2) en la tabla de la normal estándar obteniendo 0,9772","La probabilidad de que X sea menor que 58 es del 97,72 por ciento","Para P(42 < X < 58) calculamos P(Z < 2) - P(Z < -2) = 0,9772 - 0,0228 = 0,9544"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la intersección de una recta y un plano sustituimos las ecuaciones paramétricas de la recta en el plano","Obtenemos una ecuación lineal en el parámetro t que resolvemos directamente","Si la ecuación tiene solución única la recta corta al plano en un punto","Sustituimos el valor de t en las paramétricas para obtener las coordenadas del punto de intersección","Si la ecuación no tiene solución la recta es paralela al plano y si tiene infinitas está contenida en él"]'),
('matematicas', 'bachillerato', '{2}', '["Para aplicar el teorema central del límite tomamos muestras de tamaño n de una población cualquiera","Si n es suficientemente grande (n mayor o igual a 30) la media muestral sigue aproximadamente una normal","La media de la distribución muestral coincide con la media poblacional mu","La desviación típica de la media muestral es sigma / raíz(n)","Este resultado permite hacer inferencia estadística sin conocer la distribución de la población original"]'),
('matematicas', 'bachillerato', '{2}', '["Para determinar si dos planos son paralelos perpendiculares o secantes comparamos sus normales","Si las normales son proporcionales los planos son paralelos o coincidentes","Si el producto escalar de las normales es cero los planos son perpendiculares","Si las normales no son proporcionales ni perpendiculares los planos se cortan en una recta","La recta de intersección se obtiene resolviendo el sistema formado por las ecuaciones de ambos planos"]'),
('matematicas', 'bachillerato', '{2}', '["Para el cálculo de primitivas inmediatas reconocemos la estructura del integrando","La integral de x^n es x^(n+1)/(n+1) + C para n distinto de -1","La integral de e^x es e^x + C y la de 1/x es ln|x| + C","La integral de cos(x) es sen(x) + C y la de sen(x) es -cos(x) + C","Combinando estas primitivas con linealidad podemos integrar sumas y diferencias de funciones elementales"]'),
('matematicas', 'bachillerato', '{2}', '["Para resolver una ecuación matricial AX = B donde A es invertible despejamos X = A⁻¹·B","Calculamos la inversa de A hallando primero su determinante y después su adjunta","La inversa es A⁻¹ = (1/det A)·adj(A) donde adj es la traspuesta de la matriz de cofactores","Multiplicamos A⁻¹ por B para obtener la solución X","Comprobamos que A·X = B sustituyendo X en la ecuación original"]'),
('matematicas', 'bachillerato', '{2}', '["Para demostrar que tres puntos no están alineados en el espacio formamos dos vectores con ellos","Si el producto vectorial de esos vectores es el vector nulo los puntos están alineados","Si el producto vectorial es distinto del vector nulo los tres puntos definen un plano","El módulo del producto vectorial nos da el doble del área del triángulo que forman","Tres puntos alineados no determinan un plano único ya que infinitos planos los contienen"]'),
('matematicas', 'bachillerato', '{2}', '["Para hallar la proyección ortogonal de un vector u sobre otro v usamos proy = (u·v / |v|²)·v","Calculamos el producto escalar u·v sumando los productos de componentes correspondientes","Calculamos |v|² como la suma de los cuadrados de las componentes de v","Dividimos el producto escalar entre el módulo cuadrado y multiplicamos por el vector v","El vector proyección tiene la dirección de v y longitud |u|·cos(alfa) donde alfa es el ángulo entre ambos"]'),
('matematicas', 'bachillerato', '{2}', '["El error de tipo I en un contraste de hipótesis consiste en rechazar H0 siendo verdadera","La probabilidad de cometer error de tipo I coincide con el nivel de significación alfa","El error de tipo II consiste en no rechazar H0 siendo falsa y su probabilidad es beta","La potencia del contraste es 1 - beta que mide la capacidad de detectar diferencias reales","Al disminuir alfa aumenta beta y viceversa; solo aumentar n mejora ambos simultáneamente"]'),
('matematicas', 'bachillerato', '{2}', '["Para calcular la longitud de una curva y = f(x) entre a y b integramos el arco diferencial","El elemento de arco es ds = raíz(1 + (f prima(x))²) dx","La longitud total es L = integral de a hasta b de raíz(1 + (f prima)²) dx","Calculamos la derivada f prima(x) y la sustituimos en la expresión del integrando","La integral resultante puede requerir sustitución trigonométrica o métodos numéricos"]'),
('matematicas', 'bachillerato', '{2}', '["Para aplicar el teorema de Rouché-Frobenius al sistema AX = b calculamos el rango de A y de la ampliada","Menorizamos eliminando filas y columnas hasta encontrar el mayor menor no nulo de A","El rango de A es el orden del mayor menor con determinante distinto de cero","Repetimos el proceso con la matriz ampliada (A|b) para hallar su rango","Comparamos ambos rangos con el número de incógnitas para clasificar el sistema"]'),
('matematicas', 'bachillerato', '{2}', '["Para resolver una integral con raíces cuadráticas del tipo raíz(a² - x²) usamos la sustitución x = a·sen(t)","Con este cambio raíz(a² - x²) se simplifica a a·cos(t) eliminando la raíz","Calculamos dx = a·cos(t)·dt y sustituimos todo en la integral original","Resolvemos la integral trigonométrica resultante con las técnicas habituales","Deshacemos la sustitución usando t = arcsen(x/a) para volver a la variable original"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('quimica', 'bachillerato', '{2}', '["Para escribir la configuración electrónica de un átomo primero ordenamos los subniveles por energía","Seguimos el orden 1s, 2s, 2p, 3s, 3p, 4s, 3d, 4p usando el diagrama de Möller","Llenamos cada subnivel respetando el número máximo de electrones: 2 para s, 6 para p, 10 para d","El principio de exclusión de Pauli impide que dos electrones tengan los cuatro números cuánticos iguales","La regla de Hund obliga a semiocupar los orbitales antes de emparejar electrones en un mismo subnivel"]'),
('quimica', 'bachillerato', '{2}', '["Para ajustar una reacción redox en medio ácido primero separamos en semirreacciones de oxidación y reducción","En cada semirreacción ajustamos los átomos del elemento que se oxida o reduce","Equilibramos el oxígeno añadiendo moléculas de agua al lado que le faltan","Equilibramos el hidrógeno añadiendo iones H⁺ al lado que le faltan","Igualamos los electrones ganados y perdidos y sumamos ambas semirreacciones simplificando"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular el pH de un ácido débil HA con concentración C y constante Ka planteamos el equilibrio","El ácido se disocia parcialmente: HA ⇌ H⁺ + A⁻ con Ka = [H⁺][A⁻]/[HA]","Si llamamos x a la concentración de H⁺ en equilibrio entonces Ka = x²/(C - x)","Si Ka es pequeña podemos aproximar C - x ≈ C y obtenemos x = raíz(Ka·C)","El pH se calcula como pH = -log(x) y comprobamos que la aproximación es válida"]'),
('quimica', 'bachillerato', '{2}', '["Para nombrar un compuesto orgánico con nomenclatura IUPAC localizamos la cadena carbonada más larga","La cadena principal incluye el grupo funcional de mayor prioridad que da nombre al compuesto","Numeramos la cadena empezando por el extremo que da los localizadores más bajos al grupo funcional","Nombramos los sustituyentes por orden alfabético indicando su posición con un número","Unimos todos los componentes en un solo nombre separando números con comas y del nombre con guiones"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular la constante Kc de un equilibrio a partir de concentraciones iniciales usamos un ICE","En la tabla ICE anotamos las concentraciones iniciales, el cambio y las de equilibrio","El cambio se expresa con una incógnita x según la estequiometría de la reacción","Sustituimos las expresiones de equilibrio en la expresión de Kc y resolvemos la ecuación","Comprobamos que los valores de concentración obtenidos son todos positivos y coherentes"]'),
('quimica', 'bachillerato', '{2}', '["La geometría molecular se predice con el modelo RPECV de repulsión de pares electrónicos","Dibujamos la estructura de Lewis contando electrones de valencia y asignando pares enlazantes y libres","Contamos los pares de electrones alrededor del átomo central incluyendo los pares solitarios","Los pares se disponen para minimizar la repulsión: 2 pares lineales, 3 trigonal plana, 4 tetraédrica","Los pares solitarios modifican los ángulos de enlace dando geometrías como angular o piramidal"]'),
('quimica', 'bachillerato', '{2}', '["Para ajustar una reacción redox en medio básico primero la ajustamos como si fuera en medio ácido","Separamos en semirreacciones, ajustamos átomos, oxígenos con agua e hidrógenos con H⁺","Igualamos electrones y sumamos las semirreacciones obteniendo la ecuación ajustada en medio ácido","Añadimos tantos OH⁻ como H⁺ haya en ambos lados y los combinamos formando agua","Simplificamos las moléculas de agua que aparezcan en ambos lados de la ecuación"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular la solubilidad de una sal poco soluble usamos su producto de solubilidad Kps","Escribimos el equilibrio de disolución: AB₂(s) ⇌ A²⁺(aq) + 2B⁻(aq)","Si la solubilidad molar es s entonces [A²⁺] = s y [B⁻] = 2s","Sustituimos en Kps = s·(2s)² = 4s³ y despejamos s = (Kps/4)^(1/3)","El efecto del ion común reduce la solubilidad si añadimos una sal con un ion en común"]'),
('quimica', 'bachillerato', '{2}', '["Una disolución reguladora o tampón contiene un ácido débil y su base conjugada en concentraciones similares","Al añadir un ácido fuerte los H⁺ reaccionan con la base conjugada A⁻ formando HA","Al añadir una base fuerte los OH⁻ reaccionan con el ácido HA formando A⁻ y agua","El pH del tampón se calcula con la ecuación de Henderson-Hasselbalch: pH = pKa + log([A⁻]/[HA])","El tampón mantiene el pH casi constante mientras no se sobrepase su capacidad reguladora"]'),
('quimica', 'bachillerato', '{2}', '["La entalpía estándar de una reacción se calcula usando la ley de Hess y entalpías de formación","La entalpía de reacción es la suma de entalpías de formación de productos menos la de reactivos","Cada entalpía de formación se multiplica por su coeficiente estequiométrico correspondiente","Una entalpía de reacción negativa indica que la reacción es exotérmica y libera calor","El ciclo de Born-Haber aplica la ley de Hess al proceso de formación de compuestos iónicos"]'),
('quimica', 'bachillerato', '{2}', '["Para determinar el orden de una reacción cinética medimos la velocidad a distintas concentraciones","Si al duplicar la concentración de A la velocidad se duplica el orden respecto a A es 1","Si al duplicar la concentración la velocidad se cuadruplica el orden respecto a A es 2","La ley de velocidad es v = k·[A]^m·[B]^n donde m y n son los órdenes parciales","El orden total de la reacción es la suma de los órdenes parciales m + n"]'),
('quimica', 'bachillerato', '{2}', '["Para predecir la espontaneidad de una reacción usamos la energía libre de Gibbs deltaG = deltaH - T·deltaS","Si deltaG es negativo la reacción es espontánea en las condiciones dadas","Si deltaH es negativo y deltaS es positivo la reacción es siempre espontánea","Si deltaH es positivo y deltaS es negativo la reacción nunca es espontánea","Si tienen el mismo signo la espontaneidad depende de la temperatura"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular la fem de una pila electroquímica restamos los potenciales estándar de reducción","La fem es E = E cátodo - E ánodo donde el ánodo es el electrodo con menor potencial","Si la fem resulta positiva la pila funciona espontáneamente generando corriente eléctrica","La ecuación de Nernst permite calcular la fem a concentraciones distintas de las estándar","E = E° - (RT/nF)·ln(Q) donde Q es el cociente de reacción y n los electrones transferidos"]'),
('quimica', 'bachillerato', '{2}', '["La hidrólisis de una sal determina si su disolución acuosa es ácida, básica o neutra","Una sal de ácido fuerte y base fuerte como NaCl no se hidroliza y el pH es neutro","Una sal de ácido débil y base fuerte como CH3COONa se hidroliza dando un pH básico","Una sal de ácido fuerte y base débil como NH4Cl se hidroliza dando un pH ácido","El ion procedente del ácido o base débil es el que reacciona con el agua alterando el pH"]'),
('quimica', 'bachillerato', '{2}', '["Las reacciones de adición se producen en compuestos con dobles o triples enlaces","El alqueno reacciona con HBr añadiendo H y Br a los carbonos del doble enlace","La regla de Markovnikov indica que el H se une al carbono con más hidrógenos","Se forma un haloalcano como producto mayoritario siguiendo esta regla","La adición anti-Markovnikov ocurre en presencia de peróxidos por un mecanismo radicalario"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular el grado de disociación alfa de un electrolito débil usamos la constante de equilibrio","Si la concentración inicial es C y el grado de disociación es alfa, la concentración disociada es C·alfa","Sustituimos en la expresión de Ka obteniendo Ka = C·alfa² / (1 - alfa)","Si alfa es muy pequeño (menor que 0,05) aproximamos 1 - alfa ≈ 1 y alfa = raíz(Ka/C)","Comprobamos que la aproximación es válida verificando que alfa resulta efectivamente menor que 0,05"]'),
('quimica', 'bachillerato', '{2}', '["La electrólisis del cloruro de sodio fundido descompone la sal mediante corriente eléctrica","En el cátodo se reducen los iones Na⁺ ganando electrones y formando sodio metálico","En el ánodo se oxidan los iones Cl⁻ perdiendo electrones y formando gas cloro","La cantidad de sustancia depositada se calcula con las leyes de Faraday","Un faraday equivale a 96485 culombios que es la carga de un mol de electrones"]'),
('quimica', 'bachillerato', '{2}', '["Los isómeros estructurales tienen la misma fórmula molecular pero diferente conectividad entre átomos","El butanol tiene cuatro isómeros: 1-butanol, 2-butanol, 2-metil-1-propanol y 2-metil-2-propanol","Los isómeros de posición difieren en la ubicación del grupo funcional en la cadena","Los isómeros de cadena difieren en la ramificación del esqueleto carbonado","Los isómeros de función tienen distintos grupos funcionales como un alcohol y un éter"]'),
('quimica', 'bachillerato', '{2}', '["El principio de Le Chatelier predice el desplazamiento del equilibrio ante una perturbación","Si aumentamos la concentración de un reactivo el equilibrio se desplaza hacia los productos","Si disminuimos el volumen a temperatura constante el equilibrio favorece el lado con menos moles de gas","Si aumentamos la temperatura el equilibrio se desplaza en el sentido endotérmico","Un catalizador no desplaza el equilibrio, solo acelera igualmente las reacciones directa e inversa"]'),
('quimica', 'bachillerato', '{2}', '["Para preparar una disolución de concentración exacta pesamos la masa necesaria de soluto","Disolvemos el soluto en un poco de disolvente en un vaso de precipitados","Trasvasamos la disolución a un matraz aforado del volumen deseado enjuagando bien el vaso","Añadimos disolvente hasta alcanzar exactamente la línea de enrase del matraz aforado","Tapamos y agitamos por inversión varias veces para homogeneizar la disolución"]'),
('quimica', 'bachillerato', '{2}', '["Los enlaces intermoleculares determinan las propiedades físicas de las sustancias moleculares","Las fuerzas de dispersión de London actúan en todas las moléculas y aumentan con la masa molecular","Las fuerzas dipolo-dipolo actúan entre moléculas polares y son más intensas que las de London","Los puentes de hidrógeno se forman cuando el hidrógeno está unido a F, O o N muy electronegativos","El agua tiene un punto de ebullición anormalmente alto debido a sus puentes de hidrógeno"]'),
('quimica', 'bachillerato', '{2}', '["La velocidad de una reacción aumenta con la temperatura según la ecuación de Arrhenius","k = A·e^(-Ea/RT) donde Ea es la energía de activación y A el factor de frecuencia","Un catalizador disminuye la energía de activación ofreciendo un camino de reacción alternativo","Al reducir Ea el exponencial aumenta y la constante de velocidad k crece significativamente","El catalizador no cambia el deltaG de la reacción ni la posición del equilibrio"]'),
('quimica', 'bachillerato', '{2}', '["Para valorar un ácido poliprótico como el H2SO4 diluido con NaOH observamos dos puntos de equivalencia","En el primer punto de equivalencia se neutraliza el primer protón formando NaHSO4","Se necesita el mismo volumen de base para alcanzar el segundo punto de equivalencia","En el segundo punto de equivalencia todo el ácido se ha convertido en Na2SO4","La curva de valoración muestra dos saltos de pH uno por cada protón neutralizado"]'),
('quimica', 'bachillerato', '{2}', '["La teoría de bandas explica la conductividad eléctrica de sólidos cristalinos","En los metales la banda de valencia y la de conducción se solapan permitiendo el flujo de electrones","En los aislantes hay una banda prohibida ancha que los electrones no pueden cruzar","En los semiconductores la banda prohibida es estrecha y la temperatura puede dar energía suficiente","El dopaje de semiconductores con impurezas crea portadores adicionales mejorando la conductividad"]'),
('quimica', 'bachillerato', '{2}', '["Las reacciones de condensación entre un ácido carboxílico y un alcohol producen un éster y agua","El catalizador ácido protona el grupo carbonilo del ácido facilitando el ataque del alcohol","Se forma un intermediario tetraédrico que pierde una molécula de agua","El éster resultante se identifica por su olor afrutado característico","La reacción es reversible y la hidrólisis del éster regenera el ácido y el alcohol originales"]'),
('quimica', 'bachillerato', '{2}', '["La corrosión del hierro es un proceso electroquímico de oxidación en presencia de agua y oxígeno","El hierro se oxida a Fe²⁺ perdiendo electrones en las zonas anódicas de la superficie","Los electrones viajan a las zonas catódicas donde el oxígeno se reduce formando iones OH⁻","Los iones Fe²⁺ y OH⁻ forman hidróxido ferroso que se oxida a óxido de hierro hidratado o herrumbre","La protección catódica conecta el hierro a un metal más reductor como el cinc que se sacrifica"]'),
('quimica', 'bachillerato', '{2}', '["La hibridación sp3 del carbono mezcla un orbital s y tres p formando cuatro orbitales equivalentes","Los cuatro orbitales híbridos sp3 se disponen en geometría tetraédrica con ángulos de 109,5 grados","En la hibridación sp2 se mezclan un orbital s y dos p dejando un orbital p sin hibridar","Los tres orbitales sp2 forman ángulos de 120 grados en geometría trigonal plana","El orbital p no hibridado forma el enlace pi del doble enlace entre dos carbonos sp2"]'),
('quimica', 'bachillerato', '{2}', '["El enlace metálico se explica con el modelo del mar de electrones","Los cationes metálicos se ordenan en una red cristalina rodeados de electrones deslocalizados","Los electrones libres se mueven por toda la estructura permitiendo la conducción eléctrica y térmica","La deslocalización electrónica explica la maleabilidad y ductilidad de los metales","La fuerza del enlace metálico aumenta con el número de electrones de valencia y disminuye con el radio iónico"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular la Kp de un equilibrio gaseoso a partir de Kc usamos la relación Kp = Kc·(RT)^delta n","Delta n es la diferencia entre moles de productos gaseosos y moles de reactivos gaseosos","Si delta n = 0 entonces Kp = Kc y las constantes de equilibrio coinciden","Las presiones parciales de cada gas se relacionan con la presión total y la fracción molar","Al expresar Kp usamos presiones parciales en lugar de concentraciones molares"]'),
('quimica', 'bachillerato', '{2}', '["La saponificación es la hidrólisis alcalina de un éster graso con hidróxido de sodio","El triglicérido reacciona con tres moléculas de NaOH en medio caliente","Se obtiene glicerol y tres moléculas de jabón que son sales sódicas de ácidos grasos","El jabón tiene una parte hidrófila (carboxilato sódico) y otra hidrófoba (cadena hidrocarbonada)","En el agua el jabón forma micelas que atrapan la grasa en su interior permitiendo su disolución"]'),
('quimica', 'bachillerato', '{2}', '["Los polímeros de adición se forman por la apertura del doble enlace de monómeros insaturados","El etileno se polimeriza abriendo su doble enlace C=C y uniendo miles de unidades en cadena","El polietileno resultante es un polímero termoplástico ampliamente usado en envases","Los polímeros de condensación liberan una molécula pequeña como agua en cada unión","El nailon se forma por condensación entre un diácido y una diamina liberando agua en cada enlace"]'),
('quimica', 'bachillerato', '{2}', '["La estructura de Lewis del CO2 muestra un carbono con dobles enlaces a cada oxígeno sin pares solitarios en el C","La molécula es lineal con ángulo de enlace de 180 grados y sin momento dipolar neto","La del H2O muestra un oxígeno con dos pares enlazantes y dos pares solitarios","Los pares solitarios comprimen el ángulo de enlace de 109,5 a unos 104,5 grados","La geometría angular del agua y sus pares libres le confieren un elevado momento dipolar"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular el pH en el punto de equivalencia de una valoración ácido débil-base fuerte","En el punto de equivalencia solo queda la base conjugada del ácido débil en disolución","La base conjugada se hidroliza parcialmente produciendo OH⁻: A⁻ + H2O ⇌ HA + OH⁻","Calculamos Kb = Kw/Ka y resolvemos para [OH⁻] con la fórmula de ácido débil adaptada","Obtenemos el pOH y de ahí el pH que resulta mayor que 7 por tratarse de una base en disolución"]'),
('quimica', 'bachillerato', '{2}', '["La energía reticular mide la estabilidad del cristal iónico y depende de cargas y distancias","Según la ley de Coulomb, a mayor carga de los iones más fuerte es la atracción y mayor la energía reticular","A menor distancia interiónica (iones más pequeños) mayor es la energía reticular","El cloruro de sodio tiene menor energía reticular que el óxido de magnesio por sus menores cargas","La energía reticular se puede calcular experimentalmente con el ciclo de Born-Haber"]'),
('quimica', 'bachillerato', '{2}', '["Las propiedades periódicas varían de forma predecible a lo largo de la tabla periódica","El radio atómico disminuye a lo largo de un periodo al aumentar la carga nuclear efectiva","La energía de ionización aumenta a lo largo de un periodo porque cuesta más arrancar un electrón","La electronegatividad aumenta hacia la derecha y hacia arriba en la tabla periódica","La afinidad electrónica es mayor en los halógenos que están cerca de completar su capa de valencia"]'),
('quimica', 'bachillerato', '{2}', '["Los aminoácidos son moléculas con un grupo amino y un grupo carboxilo unidos al carbono alfa","En disolución acuosa a pH neutro el aminoácido existe como zwitterión con ambos grupos ionizados","El punto isoeléctrico es el pH al que el aminoácido tiene carga neta cero","Los aminoácidos se unen por enlace peptídico liberando una molécula de agua","La cadena polipeptídica resultante constituye la estructura primaria de la proteína"]'),
('quimica', 'bachillerato', '{2}', '["Para calcular la variación de entropía en una reacción sumamos las entropías estándar de los productos","A cada entropía la multiplicamos por su coeficiente estequiométrico","Restamos la suma de las entropías estándar de los reactivos multiplicadas por sus coeficientes","Las reacciones que producen más moles de gas suelen tener delta S positivo","Un delta S positivo indica que el desorden del sistema aumenta durante la reacción"]'),
('quimica', 'bachillerato', '{2}', '["La oxidación de un alcohol primario con un oxidante suave produce un aldehído","Si el oxidante es fuerte el aldehído se sigue oxidando a ácido carboxílico","La oxidación de un alcohol secundario produce una cetona independientemente del oxidante","Los alcoholes terciarios no se oxidan porque no tienen hidrógeno en el carbono funcional","El permanganato de potasio y el dicromato de potasio son los oxidantes más utilizados en laboratorio"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'bachillerato', '{1}', '["Se identifica una necesidad o problema tecnológico que requiere una solución técnica","Se busca información y se analizan soluciones existentes para problemas similares","Se diseñan varias propuestas de solución evaluando materiales, costes y viabilidad","Se construye un prototipo funcional siguiendo los planos del diseño seleccionado","Se evalúa el prototipo, se corrigen fallos y se documenta todo el proceso"]'),
('tecnologia', 'bachillerato', '{1}', '["La corriente eléctrica fluye desde el polo positivo de la batería a través del circuito","La resistencia limita la intensidad de corriente según la ley de Ohm: I = V/R","El amperímetro se conecta en serie para medir la intensidad que atraviesa el circuito","El voltímetro se conecta en paralelo para medir la caída de tensión en un componente","La potencia consumida por la resistencia se calcula como P = V por I en vatios"]'),
('tecnologia', 'bachillerato', '{1}', '["Una puerta lógica AND recibe dos entradas A y B y produce una salida","La salida es 1 únicamente cuando ambas entradas A y B son simultáneamente 1","La puerta OR produce salida 1 cuando al menos una de las entradas es 1","La puerta NOT invierte la señal de entrada: si entra 1 sale 0 y viceversa","Combinando estas puertas básicas se pueden diseñar circuitos digitales complejos"]'),
('tecnologia', 'bachillerato', '{1}', '["Un mecanismo de biela-manivela convierte movimiento circular en rectilíneo alternativo","La manivela gira solidaria a un eje motor describiendo un movimiento circular completo","La biela conecta la manivela con el émbolo transmitiendo el movimiento","El émbolo se desplaza linealmente dentro del cilindro con un recorrido igual al doble del radio","Este mecanismo es el fundamento del motor de combustión interna de cuatro tiempos"]'),
('tecnologia', 'bachillerato', '{1}', '["Un transistor bipolar NPN tiene tres terminales: emisor, base y colector","Una pequeña corriente en la base permite el paso de una corriente mucho mayor entre colector y emisor","En estado de corte no circula corriente por la base y el transistor actúa como interruptor abierto","En estado de saturación la corriente de base es suficiente para que conduzca al máximo","El transistor puede funcionar como amplificador en la zona activa o como conmutador digital"]'),
('tecnologia', 'bachillerato', '{1}', '["Un sistema de engranajes transmite el movimiento rotatorio entre dos ejes mediante dientes encajados","Si la rueda motriz tiene menos dientes que la conducida se produce una reducción de velocidad","La relación de transmisión es el cociente entre el número de dientes de la conducida y la motriz","El par o torque aumenta proporcionalmente a la reducción de velocidad obtenida","Los trenes de engranajes combinan varias etapas para conseguir relaciones de transmisión elevadas"]'),
('tecnologia', 'bachillerato', '{1}', '["El diodo semiconductor permite el paso de corriente en un solo sentido llamado polarización directa","En polarización inversa el diodo bloquea la corriente actuando como un circuito abierto","El diodo LED emite luz cuando se polariza directamente consumiendo muy poca energía","Un puente de diodos rectifica la corriente alterna convirtiéndola en corriente continua pulsante","Un condensador en paralelo filtra las pulsaciones suavizando la señal de corriente continua"]'),
('tecnologia', 'bachillerato', '{1}', '["Un sensor de temperatura detecta cambios térmicos y convierte la temperatura en una señal eléctrica","La señal analógica del sensor se envía a un conversor analógico-digital para su procesamiento","El microcontrolador lee el valor digital y lo compara con un umbral programado","Si la temperatura supera el umbral el microcontrolador activa una señal de salida","Un actuador como un ventilador se enciende automáticamente para enfriar el sistema"]'),
('tecnologia', 'bachillerato', '{1}', '["El motor de corriente continua convierte energía eléctrica en movimiento rotatorio","La corriente circula por las bobinas del rotor creando un campo magnético","Este campo interactúa con los imanes del estátor produciendo un par de fuerzas","El conmutador invierte la corriente en las bobinas para mantener el giro continuo","La velocidad del motor se puede regular variando el voltaje aplicado o la señal PWM"]'),
('tecnologia', 'bachillerato', '{1}', '["Un circuito con resistencias en serie y paralelo se simplifica paso a paso","Primero identificamos las resistencias que están en paralelo y calculamos su equivalente","Sustituimos el paralelo por su equivalente y lo sumamos con las resistencias en serie","Repetimos el proceso hasta obtener una única resistencia total del circuito","Con la resistencia total y el voltaje de la fuente calculamos la corriente total usando la ley de Ohm"]'),
('tecnologia', 'bachillerato', '{1}', '["La neumática utiliza aire comprimido para transmitir energía y producir movimiento","Un compresor aspira aire atmosférico y lo comprime almacenándolo en un depósito o calderín","Las válvulas distribuidoras controlan la dirección del flujo de aire hacia los actuadores","El cilindro neumático de doble efecto convierte la presión del aire en movimiento lineal","El aire utilizado se expulsa a la atmósfera sin contaminar a diferencia de los sistemas hidráulicos"]'),
('tecnologia', 'bachillerato', '{1}', '["La hidráulica utiliza fluidos incompresibles para transmitir fuerzas a grandes distancias","Una bomba hidráulica genera la presión necesaria en el circuito moviendo el fluido","Las válvulas de control regulan el caudal, la presión y la dirección del fluido","Los cilindros hidráulicos convierten la presión del fluido en fuerza lineal de gran potencia","El principio de Pascal explica que la presión se transmite íntegramente en todas las direcciones"]'),
('tecnologia', 'bachillerato', '{1}', '["Se plantea el diseño de un circuito combinacional a partir de una tabla de verdad","Se identifica la expresión booleana que describe la función lógica usando los unos de la salida","Se simplifica la expresión usando álgebra de Boole o mapas de Karnaugh","Se dibuja el circuito con las puertas lógicas correspondientes a la expresión simplificada","Se verifica el circuito comprobando que las salidas coinciden con la tabla de verdad original"]'),
('tecnologia', 'bachillerato', '{1}', '["La estructura de un puente debe soportar las cargas sin deformarse excesivamente ni romperse","Los elementos sometidos a tracción se estiran y los sometidos a compresión se acortan","Las vigas soportan cargas mediante esfuerzos de flexión combinando tracción y compresión","La triangulación refuerza la estructura porque los triángulos son indeformables bajo carga","Los materiales se seleccionan según su resistencia mecánica, peso y coste para cada función estructural"]'),
('tecnologia', 'bachillerato', '{1}', '["Un condensador almacena energía eléctrica en un campo eléctrico entre dos placas conductoras","La capacidad C se mide en faradios y depende del área de las placas y la distancia entre ellas","Al conectar el condensador a una batería se carga exponencialmente con constante de tiempo RC","La energía almacenada es E = medio C por V al cuadrado y se libera al descargar","Los condensadores se usan para filtrado, desacoplo, temporización y almacenamiento de energía"]'),
('tecnologia', 'bachillerato', '{1}', '["Un sistema de poleas y correas transmite el movimiento entre ejes situados a cierta distancia","La polea motriz gira accionada por un motor y arrastra la correa por rozamiento","La correa transmite el movimiento a la polea conducida haciendo girar el segundo eje","La relación de transmisión depende de los diámetros de ambas poleas","Si la polea conducida tiene el doble de diámetro que la motriz gira a la mitad de velocidad"]'),
('tecnologia', 'bachillerato', '{1}', '["Un autómata programable o PLC recibe señales de los sensores conectados a sus entradas","El programa almacenado en la memoria del PLC procesa las señales según la lógica definida","Las salidas del PLC activan o desactivan actuadores como motores, válvulas o luces","El ciclo de scan del PLC lee entradas, ejecuta el programa y actualiza las salidas continuamente","Los PLC se programan habitualmente en lenguaje ladder o diagrama de contactos"]'),
('tecnologia', 'bachillerato', '{1}', '["La domótica integra sistemas tecnológicos en el hogar para automatizar funciones cotidianas","Los sensores detectan condiciones como luminosidad, temperatura, presencia o humedad","Un controlador central procesa la información y toma decisiones según reglas programadas","Los actuadores ejecutan las órdenes encendiendo luces, regulando la calefacción o bajando persianas","La comunicación entre dispositivos puede ser por cable, wifi, zigbee o bluetooth"]'),
('tecnologia', 'bachillerato', '{1}', '["El acero se obtiene reduciendo el mineral de hierro con carbón de coque en un alto horno","El hierro fundido contiene demasiado carbono y se refina en un convertidor para obtener acero","Las aleaciones de acero con cromo y níquel producen acero inoxidable resistente a la corrosión","El aluminio se obtiene por electrólisis de la bauxita y es ligero pero menos resistente que el acero","Los plásticos técnicos como el policarbonato ofrecen transparencia y resistencia al impacto"]'),
('tecnologia', 'bachillerato', '{1}', '["Un circuito oscilador 555 en modo astable genera una onda cuadrada de frecuencia configurable","La frecuencia depende de las resistencias R1 y R2 y del condensador C conectados al temporizador","Al encender el circuito el condensador se carga a través de R1 y R2 hasta alcanzar 2/3 de Vcc","Al llegar a ese umbral el 555 conmuta y el condensador se descarga a través de R2","El ciclo de carga y descarga se repite indefinidamente generando la señal periódica"]'),
('tecnologia', 'bachillerato', '{1}', '["El mecanismo de tornillo sin fin y corona convierte el movimiento rotatorio con gran reducción","El tornillo sin fin gira accionado por el motor y cada vuelta avanza un diente de la corona","La relación de transmisión es igual al número de dientes de la corona","El sistema es irreversible: la corona no puede mover el tornillo lo que evita retrocesos","Se utiliza en ascensores, afinadores de instrumentos y sistemas de dirección de vehículos"]'),
('tecnologia', 'bachillerato', '{1}', '["Un sistema de comunicaciones digital consta de emisor, canal y receptor","El emisor codifica la información en señales digitales de ceros y unos","La señal se modula para adaptarla al canal de transmisión ya sea cable, fibra óptica o aire","El receptor demodula la señal y decodifica los bits recuperando la información original","Los protocolos de comunicación definen las reglas para que emisor y receptor se entiendan correctamente"]'),
('tecnologia', 'bachillerato', '{1}', '["La energía eólica aprovecha la energía cinética del viento para generar electricidad","Las palas del aerogenerador captan el viento y hacen girar un rotor acoplado al eje","Un multiplicador de velocidad aumenta las revoluciones entre el rotor y el generador eléctrico","El generador convierte el movimiento rotatorio en corriente eléctrica alterna","Un inversor adapta la frecuencia y el voltaje de la electricidad generada para inyectarla a la red"]'),
('tecnologia', 'bachillerato', '{1}', '["La impresión 3D por deposición de material fundido calienta un filamento termoplástico","El filamento se funde en el extrusor a temperaturas entre 180 y 250 grados centígrados","El cabezal deposita el material fundido capa a capa siguiendo las instrucciones del archivo digital","Cada capa se solidifica antes de que se deposite la siguiente formando el objeto tridimensional","El archivo STL que define la geometría se genera previamente con un programa de diseño CAD"]'),
('tecnologia', 'bachillerato', '{1}', '["La fibra óptica transmite información mediante pulsos de luz a través de un hilo de vidrio ultrapuro","La luz se propaga por el núcleo de la fibra mediante reflexión total interna","El revestimiento tiene menor índice de refracción que el núcleo impidiendo que la luz escape","La fibra óptica permite transmitir datos a velocidades de gigabits por segundo a grandes distancias","Es inmune a interferencias electromagnéticas lo que la hace superior al cable de cobre para telecomunicaciones"]'),
('tecnologia', 'bachillerato', '{1}', '["Un circuito secuencial con un biestable RS almacena un bit de información","La entrada Set pone la salida a 1 y la entrada Reset la pone a 0","El biestable mantiene su estado hasta que recibe una nueva señal de cambio","Los flip-flops D y JK son variaciones del biestable básico con funcionalidades adicionales","Combinando varios biestables se construyen registros y contadores digitales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'bachillerato', '{2}', '["Se define una variable en un programa de Python asignándole un valor con el operador igual","Se utiliza una estructura condicional if-elif-else para tomar decisiones según condiciones","Un bucle for itera sobre una lista ejecutando el bloque de código para cada elemento","Se define una función con def para encapsular un bloque de código reutilizable","El programa principal llama a la función pasando argumentos y recibe el resultado con return"]'),
('tecnologia', 'bachillerato', '{2}', '["Un sistema de control en lazo cerrado mide la salida y la compara con la referencia deseada","El sensor capta la variable de salida y genera una señal de retroalimentación","El comparador calcula el error como la diferencia entre la referencia y la medida del sensor","El controlador PID procesa el error y genera una señal de corrección para el actuador","El actuador modifica el proceso hasta que el error se minimiza y la salida alcanza el valor deseado"]'),
('tecnologia', 'bachillerato', '{2}', '["Una red de ordenadores conecta múltiples dispositivos para compartir recursos e información","El modelo OSI divide la comunicación en siete capas desde la física hasta la de aplicación","La capa de red utiliza el protocolo IP para enrutar los paquetes de datos entre redes distintas","La capa de transporte con TCP garantiza la entrega ordenada y sin errores de los datos","La capa de aplicación incluye protocolos como HTTP, FTP y SMTP que el usuario utiliza directamente"]'),
('tecnologia', 'bachillerato', '{2}', '["Un robot industrial consta de una estructura mecánica articulada con varios grados de libertad","Los servomotores proporcionan el movimiento preciso de cada articulación del brazo robótico","Los encoders en cada eje miden la posición angular y envían la información al controlador","El controlador calcula la cinemática inversa para determinar los ángulos necesarios en cada articulación","El efector final o herramienta realiza la tarea programada como soldar, pintar o ensamblar piezas"]'),
('tecnologia', 'bachillerato', '{2}', '["Un conversor analógico-digital muestrea la señal analógica a intervalos regulares de tiempo","El teorema de Nyquist establece que la frecuencia de muestreo debe ser al menos el doble de la máxima frecuencia","Cada muestra se cuantifica asignándole el valor digital más cercano según la resolución en bits","Con 8 bits se obtienen 256 niveles de cuantificación y con 16 bits más de 65000","La señal digital resultante se puede procesar, almacenar y transmitir sin degradación por ruido"]'),
('tecnologia', 'bachillerato', '{2}', '["Una base de datos relacional organiza la información en tablas con filas y columnas","Cada tabla tiene una clave primaria que identifica de forma única cada registro","Las relaciones entre tablas se establecen mediante claves foráneas que referencian otras tablas","Las consultas SQL permiten seleccionar, insertar, actualizar y eliminar datos de las tablas","La normalización elimina redundancias distribuyendo los datos en tablas relacionadas eficientemente"]'),
('tecnologia', 'bachillerato', '{2}', '["La criptografía simétrica usa la misma clave para cifrar y descifrar el mensaje","El emisor cifra el texto plano con la clave secreta generando el texto cifrado","El receptor usa la misma clave para descifrar el mensaje y recuperar el texto original","El problema es transmitir la clave de forma segura entre emisor y receptor","La criptografía asimétrica resuelve esto usando un par de claves: una pública para cifrar y otra privada para descifrar"]'),
('tecnologia', 'bachillerato', '{2}', '["Un amplificador operacional ideal tiene ganancia infinita, impedancia de entrada infinita y de salida cero","En configuración inversora la ganancia es G = -Rf/Rin determinada por las resistencias externas","La señal de entrada se aplica a la entrada inversora a través de la resistencia Rin","La resistencia de realimentación Rf conecta la salida con la entrada inversora","La salida es una versión amplificada e invertida de la señal de entrada"]'),
('tecnologia', 'bachillerato', '{2}', '["El protocolo TCP/IP establece la comunicación entre ordenadores en Internet","La capa de acceso a red gestiona la transmisión física de los datos por el medio","La capa de Internet con el protocolo IP se encarga del direccionamiento y enrutamiento","La capa de transporte con TCP o UDP gestiona la comunicación extremo a extremo","La capa de aplicación proporciona los servicios de red como navegación web y correo electrónico"]'),
('tecnologia', 'bachillerato', '{2}', '["El diseño de un circuito impreso PCB comienza con el esquema eléctrico del circuito","Se seleccionan las huellas de cada componente y se posicionan sobre la placa","El software de diseño traza las pistas de cobre que conectan los componentes según el esquema","Se genera el archivo Gerber con la información de fabricación de cada capa del PCB","La placa se fabrica mediante ataque químico o fresado CNC y se sueldan los componentes"]'),
('tecnologia', 'bachillerato', '{2}', '["Un sistema embebido es un computador dedicado a realizar funciones específicas en tiempo real","El microcontrolador integra procesador, memoria RAM, memoria flash y periféricos en un solo chip","El firmware se programa en C o en ensamblador y se graba en la memoria del microcontrolador","Los periféricos del microcontrolador incluyen ADC, UART, SPI, I2C, timers y PWM","El sistema embebido interactúa con el entorno físico a través de sensores y actuadores conectados a sus pines"]'),
('tecnologia', 'bachillerato', '{2}', '["La inteligencia artificial busca que las máquinas imiten capacidades cognitivas humanas","El aprendizaje automático o machine learning permite a los algoritmos aprender de datos sin programación explícita","Se divide el conjunto de datos en entrenamiento y validación para evaluar el modelo","El modelo se entrena ajustando sus parámetros para minimizar el error en las predicciones","El modelo entrenado se prueba con datos nuevos para verificar su capacidad de generalización"]'),
('tecnologia', 'bachillerato', '{2}', '["La arquitectura Von Neumann almacena datos e instrucciones en la misma memoria","La unidad de control lee las instrucciones de la memoria y las decodifica secuencialmente","La unidad aritmético-lógica ejecuta las operaciones matemáticas y lógicas indicadas","Los registros almacenan temporalmente los datos que el procesador está utilizando","El bus de datos, el bus de direcciones y el bus de control comunican los componentes del sistema"]'),
('tecnologia', 'bachillerato', '{2}', '["Un servomotor combina un motor de corriente continua con un potenciómetro y un circuito de control","La señal PWM indica al servo la posición angular deseada entre 0 y 180 grados","El circuito de control compara la posición actual medida por el potenciómetro con la deseada","Si hay error el motor gira hasta que el potenciómetro indica la posición correcta","Los servomotores se usan en robótica, aeromodelismo y sistemas de posicionamiento de precisión"]'),
('tecnologia', 'bachillerato', '{2}', '["Un sistema operativo gestiona los recursos del hardware y proporciona servicios a las aplicaciones","El kernel administra la memoria, el procesador, los dispositivos de entrada y salida y el almacenamiento","La gestión de procesos asigna tiempo de CPU a cada programa en ejecución mediante planificación","El sistema de archivos organiza la información en directorios y ficheros con permisos de acceso","La interfaz de usuario puede ser gráfica o de línea de comandos según las necesidades del usuario"]'),
('tecnologia', 'bachillerato', '{2}', '["El Internet de las cosas conecta dispositivos cotidianos a la red para intercambiar datos","Los sensores integrados en los dispositivos recogen información del entorno continuamente","Los datos se transmiten mediante protocolos ligeros como MQTT a una plataforma en la nube","La plataforma procesa y analiza los datos aplicando algoritmos de decisión o inteligencia artificial","Las acciones resultantes se envían de vuelta a los actuadores que modifican el entorno automáticamente"]'),
('tecnologia', 'bachillerato', '{2}', '["Una celda fotovoltaica convierte la luz solar directamente en electricidad mediante efecto fotoeléctrico","Los fotones de la luz incidente liberan electrones en el semiconductor de silicio dopado","La unión P-N del semiconductor crea un campo eléctrico que separa los portadores de carga","Los electrones fluyen por un circuito externo generando corriente continua","Un inversor convierte la corriente continua en alterna para su uso doméstico o inyección a la red"]'),
('tecnologia', 'bachillerato', '{2}', '["La programación orientada a objetos organiza el código en clases que definen propiedades y métodos","Una clase es una plantilla que describe las características y comportamientos de un tipo de objeto","Se crean instancias u objetos de la clase que tienen valores propios para cada propiedad","La herencia permite crear nuevas clases que heredan atributos y métodos de una clase padre","El polimorfismo permite que objetos de distintas clases respondan de forma diferente al mismo método"]'),
('tecnologia', 'bachillerato', '{2}', '["Un filtro paso bajo permite el paso de señales con frecuencia inferior a la frecuencia de corte","La frecuencia de corte se calcula como fc = 1/(2π·R·C) en un filtro RC de primer orden","Las señales por encima de la frecuencia de corte se atenúan progresivamente","Un filtro paso alto atenúa las frecuencias bajas y permite el paso de las altas","Combinando filtros paso bajo y paso alto se obtiene un filtro paso banda que deja pasar un rango de frecuencias"]'),
('tecnologia', 'bachillerato', '{2}', '["El protocolo HTTPS añade cifrado SSL/TLS a la comunicación HTTP entre navegador y servidor","El servidor envía su certificado digital que contiene su clave pública al navegador","El navegador verifica el certificado con la autoridad certificadora y genera una clave de sesión","La clave de sesión se cifra con la clave pública del servidor y se envía","A partir de ese momento toda la comunicación se cifra simétricamente con la clave de sesión compartida"]'),
('tecnologia', 'bachillerato', '{2}', '["Un motor paso a paso gira un ángulo exacto por cada pulso eléctrico que recibe","El ángulo de paso depende del número de polos del motor siendo típicamente 1,8 grados","Un controlador envía la secuencia de pulsos que determina la velocidad y dirección de giro","El modo de microstepping divide cada paso en fracciones para conseguir un movimiento más suave","Los motores paso a paso se usan en impresoras 3D, CNC y sistemas de posicionamiento de precisión"]'),
('tecnologia', 'bachillerato', '{2}', '["La computación en la nube ofrece recursos informáticos bajo demanda a través de Internet","El modelo IaaS proporciona infraestructura virtualizada como servidores y almacenamiento","El modelo PaaS ofrece plataformas de desarrollo sin gestionar el hardware subyacente","El modelo SaaS entrega aplicaciones completas accesibles directamente desde el navegador","La escalabilidad y el pago por uso son ventajas clave frente a la infraestructura local tradicional"]'),
('tecnologia', 'bachillerato', '{2}', '["Un bus I2C permite la comunicación serie entre un microcontrolador maestro y varios dispositivos esclavos","El bus utiliza solo dos líneas: SDA para datos y SCL para la señal de reloj","El maestro inicia la comunicación enviando la dirección del esclavo con el que quiere hablar","El esclavo direccionado responde con un bit de reconocimiento ACK confirmando la recepción","Los datos se transmiten byte a byte con un ACK después de cada byte hasta que el maestro finaliza la comunicación"]'),
('tecnologia', 'bachillerato', '{2}', '["La metodología ágil Scrum organiza el desarrollo de software en sprints de duración fija","El product owner define las historias de usuario priorizadas en el product backlog","El equipo selecciona las tareas del sprint backlog que puede completar en el sprint","Se realizan reuniones diarias de 15 minutos para sincronizar el progreso del equipo","Al final del sprint se entrega un incremento funcional y se realiza una retrospectiva de mejora"]'),
('tecnologia', 'bachillerato', '{2}', '["La blockchain es un registro distribuido e inmutable de transacciones organizadas en bloques","Cada bloque contiene un hash del bloque anterior formando una cadena enlazada criptográficamente","Los nodos de la red verifican las transacciones mediante un mecanismo de consenso","Una vez verificado, el bloque se añade a la cadena y no puede ser modificado sin alterar los siguientes","Esta tecnología garantiza la transparencia, seguridad e inmutabilidad de los registros sin intermediarios"]'),
('tecnologia', 'bachillerato', '{2}', '["Un algoritmo de ordenación como el quicksort selecciona un elemento pivote de la lista","Los elementos menores que el pivote se colocan a su izquierda y los mayores a su derecha","Se aplica recursivamente el mismo proceso a cada sublista izquierda y derecha","El caso base de la recursión es una sublista de cero o un elemento que ya está ordenada","La complejidad promedio del quicksort es O(n·log n) siendo uno de los algoritmos más eficientes"]'),
('tecnologia', 'bachillerato', '{2}', '["Un regulador de tensión lineal LM7805 convierte un voltaje mayor en 5 voltios estables","El voltaje de entrada debe ser al menos 2 voltios superior al de salida para un correcto funcionamiento","Un condensador de entrada de 330 nF filtra las fluctuaciones del voltaje de alimentación","Un condensador de salida de 100 nF estabiliza la tensión entregada a la carga","El exceso de energía se disipa en forma de calor por lo que puede necesitar un disipador térmico"]'),
('tecnologia', 'bachillerato', '{2}', '["La arquitectura cliente-servidor separa las funciones de presentación y procesamiento de datos","El cliente envía peticiones HTTP al servidor solicitando recursos o datos específicos","El servidor procesa la petición consultando la base de datos o ejecutando la lógica de negocio","El servidor devuelve una respuesta con los datos solicitados típicamente en formato JSON o HTML","El cliente renderiza la respuesta mostrando la información actualizada al usuario"]'),
('tecnologia', 'bachillerato', '{2}', '["Un sistema SCADA supervisa y controla procesos industriales en tiempo real desde un centro de operaciones","Las RTU o unidades terminales remotas adquieren datos de los sensores de campo","Los datos se transmiten por redes industriales al servidor central de supervisión","El software SCADA presenta los datos en interfaces gráficas con alarmas y tendencias históricas","Los operadores pueden enviar comandos de control desde la interfaz a los actuadores de la planta"]'),
('tecnologia', 'bachillerato', '{2}', '["Git es un sistema de control de versiones distribuido que registra los cambios en el código fuente","El desarrollador crea un repositorio local y realiza commits que registran instantáneas del proyecto","Las ramas permiten trabajar en nuevas funcionalidades sin afectar la rama principal","Una vez completada la funcionalidad se fusiona la rama con la principal mediante un merge","Los repositorios remotos como GitHub permiten la colaboración entre múltiples desarrolladores"]'),
('tecnologia', 'bachillerato', '{2}', '["Las redes neuronales artificiales se inspiran en el funcionamiento del cerebro biológico","Cada neurona artificial recibe entradas, las pondera con pesos y aplica una función de activación","Las neuronas se organizan en capas: entrada, ocultas y salida formando una red profunda","Durante el entrenamiento los pesos se ajustan mediante retropropagación del error","La red aprende a reconocer patrones y hacer predicciones mejorando con cada iteración del entrenamiento"]'),
('tecnologia', 'bachillerato', '{2}', '["Un convertidor DC-DC tipo boost eleva el voltaje de entrada a un voltaje de salida mayor","Un transistor MOSFET conmuta a alta frecuencia cargando y descargando una bobina inductora","Cuando el MOSFET se cierra la corriente fluye por la bobina almacenando energía magnética","Al abrirse el MOSFET la bobina libera la energía a través del diodo sumándose al voltaje de entrada","Un condensador de salida filtra la tensión elevada proporcionando un voltaje continuo estable"]'),
('tecnologia', 'bachillerato', '{2}', '["El diseño de una aplicación web comienza con la maquetación del frontend en HTML y CSS","JavaScript añade interactividad y lógica del lado del cliente al frontend","El backend se desarrolla con un framework como Django, Express o Spring Boot","Una API REST conecta el frontend con el backend intercambiando datos en formato JSON","La aplicación se despliega en un servidor cloud y se prueba para asegurar su correcto funcionamiento"]'),
('tecnologia', 'bachillerato', '{2}', '["Un sensor ultrasónico emite un pulso de sonido de alta frecuencia inaudible para el oído humano","El pulso viaja por el aire y se refleja al encontrar un obstáculo volviendo al sensor","El sensor mide el tiempo transcurrido entre la emisión y la recepción del eco","La distancia al objeto se calcula como d = v·t/2 donde v es la velocidad del sonido","Este sensor se usa en robots, sistemas de aparcamiento y medición de niveles de líquidos"]'),
('tecnologia', 'bachillerato', '{2}', '["La realidad virtual crea un entorno tridimensional inmersivo generado por ordenador","El casco de realidad virtual muestra imágenes estereoscópicas diferentes para cada ojo","Los sensores de movimiento rastrean la posición y orientación de la cabeza del usuario","El software actualiza la escena en tiempo real según los movimientos detectados","Los controladores hápticos permiten interactuar con objetos virtuales simulando la sensación del tacto"]');
